            <div 
              ref={scrollContainerRef} 
              className="flex-1 overflow-y-auto overflow-x-hidden p-2 md:p-4 scroll-smooth pb-24 md:pb-4"
              style={{ 
                  WebkitOverflowScrolling: 'touch',
