import React from 'react';
import { PlusIcon } from '../../constants';
import { Item } from '../../types';
import ItemTile from './ItemTile';

interface ItemGridProps {
  itemsForDisplay: (Item | null)[];
  mode: 'all' | 'grid';
  onAddItemToOrder: (item: Item) => void;
  onAssignItem: (slotIndex: number) => void;
  onRemoveItem?: (slotIndex: number) => void;
  loadMoreRef?: React.RefObject<HTMLDivElement>;
  isEditing?: boolean;
}

const ItemGrid = React.memo<ItemGridProps>(({ 
    itemsForDisplay, mode, onAddItemToOrder, onAssignItem, onRemoveItem, 
    loadMoreRef, isEditing = false 
}) => {
  const isFixedGrid = mode === 'grid';

  // Mobile: Auto height (scrollable). Tablet: Full height (fixed).
  const gridContainerClasses = isFixedGrid ? 'h-auto md:h-full' : '';

  // LAYOUT LOGIC:
  // Mobile: grid-cols-3 (Requested 3 columns). Auto rows for scrolling.
  // Tablet (md): grid-cols-5 (Preserved 5 columns). grid-rows-4 (Preserved 4 rows fixed).
  const gridClasses = isFixedGrid
    ? 'grid grid-cols-3 md:grid-cols-5 md:grid-rows-4 gap-2 md:gap-3 h-auto md:h-full'
    : 'grid grid-cols-3 md:grid-cols-5 gap-2 md:gap-3';

  return (
    <div className={gridContainerClasses}>
      <div className={gridClasses}>
        {itemsForDisplay.map((item, index) => {
          if (!item) {
            // Only allow assigning items to empty slots if we are in 'grid' mode.
            if (mode === 'all') return null;

            return (
              <button
                type="button"
                key={`placeholder-${index}`}
                onClick={() => {
                    if (isEditing) onAssignItem(index);
                }}
                disabled={!isEditing}
                className={`w-full rounded-lg border-2 border-dashed border-border 
                           flex items-center justify-center text-text-muted transition-colors 
                           aspect-square md:aspect-auto
                           ${isFixedGrid ? 'md:h-full' : ''}
                           ${isEditing ? 'cursor-pointer hover:bg-surface-muted hover:border-primary hover:text-primary bg-surface-muted/20' : 'opacity-50 cursor-default'}`}
              >
                {isEditing && <PlusIcon className="h-8 w-8" />}
              </button>
            );
          }

          return (
            <ItemTile
                key={`${item.id}-${index}`}
                item={item}
                mode={mode}
                onAddItemToOrder={onAddItemToOrder}
                onAssignItem={onAssignItem}
                onRemoveFromGrid={onRemoveItem}
                index={index}
                isFixedGrid={isFixedGrid}
                isEditing={isEditing}
            />
          );
        })}
      </div>
      {/* Sentinel for infinite scrolling */}
      {loadMoreRef && itemsForDisplay.length > 0 && (
          <div ref={loadMoreRef} className="h-20 w-full flex items-center justify-center mt-4">
              <div className="w-2 h-2 bg-surface-muted rounded-full"></div>
          </div>
      )}
    </div>
  );
});

export default ItemGrid;

import React from 'react';
import { Item } from '../../types';
import { TrashIcon, PencilIcon } from '../../constants';

interface ItemTileProps {
    item: Item;
    mode: 'all' | 'grid';
    onAddItemToOrder: (item: Item) => void;
    onAssignItem: (slotIndex: number) => void;
    onRemoveFromGrid?: (slotIndex: number) => void;
    index: number;
    isFixedGrid: boolean;
    isEditing: boolean;
}

const ItemTile: React.FC<ItemTileProps> = React.memo(({ 
    item, mode, onAddItemToOrder, onAssignItem, onRemoveFromGrid, 
    index, isFixedGrid, isEditing 
}) => {

    const hasRealImage = item.imageUrl && !item.imageUrl.includes('via.placeholder.com');

    // --- EDIT MODE RENDER ---
    if (isEditing && mode === 'grid') {
        return (
            <div 
                className={`relative w-full rounded-xl overflow-hidden border-2 border-dashed border-primary/60 bg-primary/5 ${isFixedGrid ? 'aspect-square md:h-full md:aspect-auto' : 'aspect-square'} animate-pulse`}
            >
                {/* Background Image (Dimmed) */}
                {hasRealImage && (
                    <img 
                        src={item.imageUrl} 
                        alt={item.name} 
                        className="absolute inset-0 w-full h-full object-cover z-0 opacity-30 grayscale pointer-events-none"
                    />
                )}

                {/* Center: Tap to Swap/Edit */}
                <button
                    type="button"
                    onClick={() => onAssignItem(index)}
                    className="absolute inset-0 flex flex-col items-center justify-center z-10 w-full h-full touch-manipulation"
                >
                    <div className="bg-primary/10 p-2 rounded-full mb-1">
                        <PencilIcon className="h-6 w-6 text-primary" />
                    </div>
                    <span className="text-[10px] uppercase font-bold text-primary bg-surface/90 px-2 py-0.5 rounded-full shadow-sm">Change</span>
                </button>

                {/* Top Right: Delete Button */}
                <button 
                    type="button"
                    onClick={(e) => {
                        e.stopPropagation();
                        if(onRemoveFromGrid) onRemoveFromGrid(index);
                    }}
                    className="absolute top-1 right-1 z-20 bg-red-500 text-white rounded-full p-1.5 shadow-md hover:bg-red-600 active:scale-90 transition-transform touch-manipulation"
                >
                    <TrashIcon className="h-4 w-4" />
                </button>

                {/* Bottom Label */}
                <div className="absolute bottom-0 left-0 right-0 p-1.5 bg-black/50 backdrop-blur-sm z-0 pointer-events-none">
                    <h3 className="font-semibold text-white text-xs text-center truncate">
                        {item.name}
                    </h3>
                </div>
            </div>
        );
    }

    // --- NORMAL MODE RENDER (SPEED OPTIMIZED) ---

    const handleClick = (e: React.MouseEvent<HTMLButtonElement>) => {
        onAddItemToOrder(item);
    };

    // Price Badge Component
    const PriceBadge = () => (
        <div className="absolute top-1 right-1 md:top-2 md:right-2 bg-black/60 text-white backdrop-blur-sm px-1.5 py-0.5 md:px-2 md:py-1 rounded-md text-[10px] md:text-xs font-bold shadow-lg z-10 tabular-nums tracking-tight border border-white/20 pointer-events-none">
            ₹{item.price.toFixed(0)}
        </div>
    );

    if (hasRealImage) {
        return (
            <button
                type="button"
                onClick={handleClick}
                // Mobile: aspect-square (fits 3x5 well). Tablet: h-full (fits grid-rows-4).
                className={`relative w-full rounded-xl overflow-hidden cursor-pointer shadow-sm border border-border/50 bg-surface-muted group ${isFixedGrid ? 'aspect-square md:h-full md:aspect-auto' : 'aspect-square'} touch-manipulation select-none`}
                aria-label={`Add ${item.name} to order`}
            >
                <div className="w-full h-full pointer-events-none relative">
                    <img 
                        src={item.imageUrl} 
                        alt={item.name} 
                        className="absolute inset-0 w-full h-full object-cover z-0"
                        loading="lazy"
                        decoding="async"
                    />

                    {/* Active State Overlay */}
                    <div className="absolute inset-0 bg-black opacity-0 group-active:opacity-20 z-30 transition-none"></div>

                    <PriceBadge />

                    {/* Gradient Overlay */}
                    <div className="absolute inset-x-0 bottom-0 h-1/2 bg-gradient-to-t from-black/80 via-black/40 to-transparent z-10"></div>

                    <div className="absolute bottom-0 left-0 right-0 p-2 z-20">
                        {/* Mobile: text-xs, line-clamp-2. Tablet: slightly larger. */}
                        <h3 className="font-bold text-white text-xs md:text-sm leading-tight text-center line-clamp-2 drop-shadow-sm">
                            {item.name}
                        </h3>
                    </div>
                </div>
            </button>
        );
    } else {
        return (
            <button
                type="button"
                onClick={handleClick}
                // Mobile: aspect-square. Tablet: h-full.
                className={`relative w-full rounded-xl cursor-pointer shadow-sm border border-border bg-surface group ${isFixedGrid ? 'aspect-square md:h-full md:aspect-auto' : 'aspect-square'} touch-manipulation select-none hover:border-primary/50`}
                aria-label={`Add ${item.name} to order`}
            >
                {/* Active Overlay */}
                <div className="absolute inset-0 bg-primary opacity-0 group-active:opacity-10 z-10 rounded-xl transition-none"></div>

                <PriceBadge />
                <div className="w-full h-full flex flex-col justify-center items-center p-2 md:p-3 text-center pointer-events-none relative z-0">
                     <div className="w-6 h-1 md:w-8 bg-primary/20 rounded-full mb-2 md:mb-3"></div>
                    {/* Mobile: text-xs. Tablet: text-base. */}
                    <h3 className="font-bold text-text-primary text-xs md:text-base leading-snug line-clamp-3">
                        {item.name}
                    </h3>
                </div>
            </button>
        );
    }
});

