self.onmessage = function(e) {
    const { items, query } = e.data;

    if (!query || !query.trim()) {
        self.postMessage([]);
        return;
    }

    const lowerQuery = query.trim().toLowerCase();

    // Perform filtering off-main-thread
    const results = items.filter(item => {
        const nameMatch = item.name.toLowerCase().includes(lowerQuery);
        const categoryMatch = item.category ? item.category.toLowerCase().includes(lowerQuery) : false;
        return nameMatch || categoryMatch;
    });

    self.postMessage(results);
};
`;

const SalesScreen: React.FC = () => {
  const { 
      openDrawer, settings, printers, addReceipt, 
      items, customGrids, addCustomGrid, updateCustomGrid, setCustomGrids,
      savedTickets, saveTicket, removeTicket,
      // Global Ticket State
      currentOrder, addToOrder, removeFromOrder, deleteLineItem, 
      updateOrderItemQuantity, clearOrder, loadOrder,
      // Global View State
      activeGridId, setActiveGridId
  } = useAppContext();
  const navigate = useNavigate();
  const location = useLocation();
  const isActive = location.pathname === '/sales';

  // --- 1. DEVICE & LAYOUT DETECTION ---
  // If Tablet/Desktop: 5 cols * 4 rows = 20
  // If Mobile: 3 cols * 5 rows = 15
  const getGridSize = () => window.innerWidth < 768 ? 15 : 20;
  const [gridSize, setGridSize] = useState(getGridSize());

  useEffect(() => {
      const handleResize = () => setGridSize(getGridSize());
      window.addEventListener('resize', handleResize);
      return () => window.removeEventListener('resize', handleResize);
  }, []);

  // Main screen view state
  const [salesView, setSalesView] = useState<SalesView>('grid');
  const [searchQuery, setSearchQuery] = useState('');
  const debouncedSearchQuery = useDebounce(searchQuery, 300);

  // Search Results from Worker
  const [workerSearchResults, setWorkerSearchResults] = useState<Item[]>([]);
  const searchWorkerRef = useRef<Worker | null>(null);

  // Ticket management state
  const [editingTicket, setEditingTicket] = useState<SavedTicket | null>(null);
  const [editingQuantityItemId, setEditingQuantityItemId] = useState<string | null>(null);
  const [tempQuantity, setTempQuantity] = useState<string>('');

  // State to track if we should print after a successful save
  const [pendingPrintAction, setPendingPrintAction] = useState(false);

  // Grid Editing State
  const [isGridEditing, setIsGridEditing] = useState(false);

  // Payment state
  const [paymentResult, setPaymentResult] = useState<{ method: string, change: number, receiptId: string, date: Date } | null>(null);

  // Pagination & Scroll State
  const [displayLimit, setDisplayLimit] = useState(40);
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const loadMoreRef = useRef<HTMLDivElement>(null);

  // Modal states
  const [isManageGridsModalOpen, setIsManageGridsModalOpen] = useState(false);
  const [isSaveModalOpen, setIsSaveModalOpen] = useState(false);
  const [isOpenTicketsModalOpen, setIsOpenTicketsModalOpen] = useState(false);
  const [isSelectItemModalOpen, setIsSelectItemModalOpen] = useState(false);
  const [isAddGridModalOpen, setIsAddGridModalOpen] = useState(false);
  const [assigningSlot, setAssigningSlot] = useState<{gridId: string, slotIndex: number} | null>(null);

  const [confirmModalState, setConfirmModalState] = useState<{
      isOpen: boolean;
      title: string;
      message: React.ReactNode;
      onConfirm: () => void;
      confirmText?: string;
      confirmButtonClass?: string;
  }>({ isOpen: false, title: '', message: '', onConfirm: () => {} });

  const [isTicketVisible, setIsTicketVisible] = useState(false);

  // Initialize Search Worker
  useEffect(() => {
      const blob = new Blob([SEARCH_WORKER_CODE], { type: 'application/javascript' });
      const worker = new Worker(URL.createObjectURL(blob));
      searchWorkerRef.current = worker;

      worker.onmessage = (e) => {
          setWorkerSearchResults(e.data);
      };

      return () => {
          worker.terminate();
      };
  }, []);

  // Post messages to worker when query or items change
  useEffect(() => {
      if (searchWorkerRef.current && debouncedSearchQuery.trim()) {
          searchWorkerRef.current.postMessage({
              items: items,
              query: debouncedSearchQuery
          });
      } else {
          setWorkerSearchResults([]);
      }
  }, [debouncedSearchQuery, items]);

  // Force scroll container reflow
  useEffect(() => {
    if (isActive && scrollContainerRef.current) {
        scrollContainerRef.current.scrollTop = 0;
    }
  }, [isActive]);

  // Reset pagination when category changes
  useEffect(() => {
    setDisplayLimit(40);
    setIsGridEditing(false);
    if (scrollContainerRef.current) {
        scrollContainerRef.current.scrollTop = 0;
    }
  }, [activeGridId, debouncedSearchQuery]);

  const handleQuantityClick = useCallback((item: OrderItem) => {
    setEditingQuantityItemId(item.lineItemId);
    setTempQuantity(item.quantity.toString());
  }, []);

  const handleQuantityChangeCommit = useCallback(() => {
    if (!editingQuantityItemId) return;
    const newQuantity = parseInt(tempQuantity, 10);
    updateOrderItemQuantity(editingQuantityItemId, newQuantity);
    setEditingQuantityItemId(null);
  }, [editingQuantityItemId, tempQuantity, updateOrderItemQuantity]);

  const handleQuantityInputChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
      if (/^\d*$/.test(e.target.value)) {
          setTempQuantity(e.target.value);
      }
  }, []);

  const handleQuantityInputKeyDown = useCallback((e: React.KeyboardEvent<HTMLInputElement>) => {
      if (e.key === 'Enter') handleQuantityChangeCommit(); 
      else if (e.key === 'Escape') setEditingQuantityItemId(null);
  }, [handleQuantityChangeCommit]);

  const handleTicketClose = useCallback(() => setIsTicketVisible(false), []);
  const handleChargeClick = useCallback(() => setSalesView('payment'), []);
  const handleOpenTicketsClick = useCallback(() => setIsOpenTicketsModalOpen(true), []);

  const handleSaveTicketClick = useCallback(() => {
      setPendingPrintAction(false); 
      setIsSaveModalOpen(true);
  }, []);

  const subtotal = useMemo(() => currentOrder.reduce((sum, item) => sum + item.price * item.quantity, 0), [currentOrder]);
  const tax = useMemo(() => settings.taxEnabled ? subtotal * (settings.taxRate / 100) : 0, [subtotal, settings]);
  const total = useMemo(() => subtotal + tax, [subtotal, tax]);

  const handleProcessPayment = useCallback((method: string, tendered: number, splitDetails?: SplitPaymentDetail[]) => {
    if (editingTicket) removeTicket(editingTicket.id);
    const receiptId = `R${Date.now()}`;
    const receiptDate = new Date();

    const optimizedItems = currentOrder.map(item => ({
        ...item,
        imageUrl: '' // Strip base64 string
    }));

    const newReceipt: Receipt = { 
        id: receiptId, 
        date: receiptDate, 
        items: optimizedItems, 
        total, 
        paymentMethod: method 
    };

    if (splitDetails && splitDetails.length > 0) {
        newReceipt.splitDetails = splitDetails;
    }

    addReceipt(newReceipt);
    setPaymentResult({ method, change: tendered - total, receiptId, date: receiptDate });
  }, [addReceipt, currentOrder, editingTicket, removeTicket, total]);

  const handleNewSale = useCallback(() => {
    setSalesView('grid'); 
    setPaymentResult(null); 
    clearOrder(); 
    setEditingTicket(null);
  }, [clearOrder]);

  const itemsForDisplay = useMemo<(Item | null)[]>(() => {
    if (debouncedSearchQuery.trim()) return workerSearchResults;
    if (activeGridId === 'All') return items;

    const grid = customGrids.find(g => g.id === activeGridId);
    if (grid) {
        const sourceIds = Array.isArray(grid.itemIds) ? grid.itemIds : [];
        const finalItemIds = new Array(gridSize).fill(null);
        for(let i = 0; i < Math.min(sourceIds.length, gridSize); i++) {
            finalItemIds[i] = sourceIds[i];
        }
        return finalItemIds.map(itemId => items.find(i => i.id === itemId) || null);
    }
    return new Array(gridSize).fill(null);
  }, [activeGridId, items, customGrids, debouncedSearchQuery, workerSearchResults, gridSize]);

  const paginatedItems = useMemo(() => {
      if (activeGridId !== 'All' && !debouncedSearchQuery.trim()) return itemsForDisplay;
      return itemsForDisplay.slice(0, displayLimit);
  }, [itemsForDisplay, displayLimit, activeGridId, debouncedSearchQuery]);

  useEffect(() => {
    if ((activeGridId !== 'All' && !debouncedSearchQuery.trim()) || paginatedItems.length >= itemsForDisplay.length) return; 

    const observer = new IntersectionObserver(
        (entries) => {
            if (entries[0].isIntersecting) {
                setDisplayLimit((prev) => prev + 20);
            }
        },
        { threshold: 0.1, rootMargin: '100px' }
    );

    if (loadMoreRef.current) observer.observe(loadMoreRef.current);
    return () => observer.disconnect();
  }, [paginatedItems.length, itemsForDisplay.length, activeGridId, debouncedSearchQuery]);


  const handleAddNewGrid = useCallback(() => setIsAddGridModalOpen(true), []);
  const handleSaveNewGrid = useCallback((name: string) => {
      addCustomGrid({ id: generateId(), name, itemIds: new Array(gridSize).fill(null) });
      setIsAddGridModalOpen(false);
  }, [addCustomGrid, gridSize]);

  const handleSaveGrids = useCallback((newGrids: CustomGrid[]) => {
      setCustomGrids(newGrids);
      setIsManageGridsModalOpen(false);
      if (activeGridId !== 'All' && !newGrids.some(g => g.id === activeGridId)) {
          setActiveGridId('All');
      }
  }, [activeGridId, setCustomGrids, setActiveGridId]);

  const handleOpenSelectItemModal = useCallback((slotIndex: number) => {
      if (activeGridId === 'All') return;
      setAssigningSlot({ gridId: activeGridId, slotIndex });
      setIsSelectItemModalOpen(true);
  }, [activeGridId]);

  const handleSelectItem = useCallback((item: Item) => {
      if (!assigningSlot) return;
      const gridToUpdate = customGrids.find(g => g.id === assigningSlot.gridId);
      if (gridToUpdate) {
          const sourceIds = Array.isArray(gridToUpdate.itemIds) ? gridToUpdate.itemIds : [];
          // Ensure array is large enough for current view
          const newItemIds = [...sourceIds];
          // Pad if necessary
          while (newItemIds.length < gridSize) newItemIds.push(null);

          newItemIds[assigningSlot.slotIndex] = item.id;
          updateCustomGrid({ ...gridToUpdate, itemIds: newItemIds });
      }
      setIsSelectItemModalOpen(false);
      setAssigningSlot(null);
  }, [assigningSlot, customGrids, updateCustomGrid, gridSize]);

  const handleRemoveItemFromGrid = useCallback((slotIndex: number) => {
    if (activeGridId === 'All') return;
    const gridToUpdate = customGrids.find(g => g.id === activeGridId);
    if (gridToUpdate) {
        const sourceIds = Array.isArray(gridToUpdate.itemIds) ? gridToUpdate.itemIds : [];
        const newItemIds = [...sourceIds];
        while (newItemIds.length < gridSize) newItemIds.push(null);

        newItemIds[slotIndex] = null;
        updateCustomGrid({ ...gridToUpdate, itemIds: newItemIds });
    }
  }, [activeGridId, customGrids, updateCustomGrid, gridSize]);

  const handleClearTicket = useCallback(() => {
    clearOrder();
    setEditingTicket(null);
    setEditingQuantityItemId(null);
  }, [clearOrder]);

  const handleLoadTicket = (ticket: SavedTicket) => {
      const loadAction = () => {
          loadOrder(ticket.items);
          setEditingTicket(ticket);
          setIsOpenTicketsModalOpen(false);
          if (window.innerWidth < 768) {
              setIsTicketVisible(true);
          }
      };
      if (currentOrder.length > 0) {
          setConfirmModalState({
              isOpen: true,
              title: 'Replace Current Order?',
              message: 'Loading a saved ticket will replace your current unsaved order. Are you sure?',
              onConfirm: loadAction,
              confirmText: 'Yes, Load Ticket',
              confirmButtonClass: 'bg-amber-500 hover:bg-amber-600'
          });
      } else {
          loadAction();
      }
  };

  const handleDeleteTicket = (ticketId: string) => {
      setConfirmModalState({
          isOpen: true,
          title: 'Delete Ticket?',
          message: 'Are you sure you want to permanently delete this ticket? This cannot be undone.',
          onConfirm: () => removeTicket(ticketId),
          confirmText: 'Delete',
          confirmButtonClass: 'bg-red-600 hover:bg-red-700'
      });
  };

  const performPrint = async (ticketItems: OrderItem[], ticketName: string) => {
      const pSubtotal = ticketItems.reduce((sum, item) => sum + item.price * item.quantity, 0);
      const pTax = settings.taxEnabled ? pSubtotal * (settings.taxRate / 100) : 0;
      const pTotal = pSubtotal + pTax;

      const printer = printers.find(p => p.interfaceType === 'Bluetooth') || printers[0];
      const result = await printBill({
          items: ticketItems,
          total: pTotal, subtotal: pSubtotal, tax: pTax,
          ticketName: ticketName,
          settings, printer,
      });
      if (!result.success) {
          alert(`Print Failed: ${result.message}`);
      }
  };

  const handlePrintRequest = useCallback(() => {
      if (editingTicket) {
          performPrint(currentOrder, editingTicket.name);
      } else {
          setPendingPrintAction(true);
          setIsSaveModalOpen(true);
      }
  }, [editingTicket, currentOrder, settings, printers]);

  const handleSaveTicketComplete = (name: string) => {
      const itemsToSave = [...currentOrder];
      saveTicket({ id: `T${Date.now()}`, name, items: itemsToSave }); 
      clearOrder(); 
      setEditingTicket(null); 
      setIsSaveModalOpen(false); 
      if (pendingPrintAction) {
          performPrint(itemsToSave, name);
          setPendingPrintAction(false); 
      }
  };

  const handlePrimarySaveAction = useCallback(() => {
      if (editingTicket) {
          saveTicket({ ...editingTicket, items: currentOrder });
          clearOrder();
          setEditingTicket(null);
          setIsTicketVisible(false);
      } else {
          setPendingPrintAction(false);
          setIsSaveModalOpen(true);
      }
  }, [editingTicket, currentOrder, saveTicket, clearOrder]);

  if (salesView === 'payment') {
    return <ChargeScreen total={total} tax={tax} subtotal={subtotal} onBack={() => setSalesView('grid')} onProcessPayment={handleProcessPayment} onNewSale={handleNewSale} paymentResult={paymentResult} orderItems={currentOrder} />;
  }

  const isViewingAll = activeGridId === 'All' || debouncedSearchQuery.trim().length > 0;

  return (
    <div className="flex h-full w-full bg-background font-sans relative overflow-hidden">

      {/* 
        LAYOUT STRATEGY:
        Mobile: 
          - Grid Area is flexible middle (Layer 0).
          - Tabs are fixed bottom (Layer 1).
          - Floating Cart is positioned absolute at the bottom of the LEFT SECTION to float over tabs/grid.
          - Ticket is separate Overlay (Layer 3).
        Tablet/Desktop:
          - Grid is Left Column.
          - Ticket is Right Column.
      */}

      {/* --- LEFT SECTION (Grid + Tabs) --- */}
      <div className="flex-1 flex flex-col min-w-0 h-full relative">
        <SalesHeader openDrawer={openDrawer} onSearchChange={setSearchQuery} searchQuery={searchQuery} />

        {/* Grid Container (Takes remaining space) */}
        <div className="flex-1 relative overflow-hidden">
            <div 
              ref={scrollContainerRef} 
              className="absolute inset-0 overflow-y-auto overflow-x-hidden p-2 md:p-4 scroll-smooth"
              style={{ WebkitOverflowScrolling: 'touch', transform: 'translateZ(0)' }}
            >
              {items.length === 0 && !debouncedSearchQuery.trim() ? (
                <div className="flex flex-col items-center justify-center h-full text-center text-text-secondary p-4">
                  <div className="max-w-md">
                    <ItemsIcon className="h-16 w-16 mx-auto text-gray-300 dark:text-gray-600" />
                    <h2 className="mt-4 text-xl font-semibold text-text-primary">Your Menu is Empty</h2>
                    <button
                      onClick={() => navigate('/items')}
                      className="mt-6 px-6 py-3 bg-primary text-primary-content font-bold rounded-lg hover:bg-primary-hover shadow-md"
                    >
                      Add Items
                    </button>
                  </div>
                </div>
              ) : (
                <div className="pb-24 md:pb-4">
                    <ItemGrid
                    itemsForDisplay={paginatedItems}
                    mode={isViewingAll ? 'all' : 'grid'}
                    onAddItemToOrder={addToOrder}
                    onAssignItem={handleOpenSelectItemModal}
                    onRemoveItem={handleRemoveItemFromGrid}
                    isEditing={!isViewingAll && isGridEditing}
                    loadMoreRef={isViewingAll ? loadMoreRef : undefined}
                    />
                </div>
              )}
            </div>
        </div>

        {/* Floating Mobile Cart Button (Moved outside overflow container to float strictly above Tabs) */}
        {currentOrder.length > 0 && (
            <div className="md:hidden absolute bottom-[50px] left-0 right-0 p-4 z-50 pointer-events-none">
                <button 
                    onClick={() => setIsTicketVisible(true)}
                    className="w-full bg-primary text-primary-content rounded-xl shadow-xl shadow-primary/30 flex items-center justify-between p-4 active:scale-[0.98] transition-transform pointer-events-auto"
                >
                    <div className="flex items-center gap-3">
                        <span className="bg-white/20 px-2.5 py-1 rounded-md text-sm font-bold backdrop-blur-sm">
                            {currentOrder.reduce((acc, item) => acc + item.quantity, 0)}
                        </span>
                        <span className="font-bold text-sm uppercase tracking-wide">View Cart</span>
                    </div>
                    <div className="flex items-center gap-2">
                        <span className="font-bold text-lg">₹{total.toFixed(2)}</span>
                        <SalesIcon className="h-5 w-5 opacity-80" />
                    </div>
                </button>
            </div>
        )}

        {/* Category Tabs - Fixed at bottom of the Left Section */}
        <div className="bg-surface border-t border-border z-40 flex-shrink-0 relative shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)]">
             <CategoryTabs
                grids={customGrids}
                activeGridId={activeGridId}
                setActiveGridId={setActiveGridId}
                onAddNew={handleAddNewGrid}
                onManage={() => setIsManageGridsModalOpen(true)}
                isSearchActive={debouncedSearchQuery.trim().length > 0}
                searchResultsCount={itemsForDisplay.length}
                searchQuery={searchQuery}
                isEditing={isGridEditing}
                onToggleEditMode={() => setIsGridEditing(prev => !prev)}
              />
        </div>
      </div>

      {/* --- TICKET SECTION --- */}
      {/* Mobile: Full Screen Overlay. Desktop: Static Right Column */}
      <div 
        className={`
            fixed inset-0 z-[60] bg-background flex flex-col
            transition-transform duration-300 ease-out will-change-transform
            md:static md:z-auto md:w-[320px] lg:w-[380px] md:border-l md:border-border md:translate-y-0
            ${isTicketVisible ? 'translate-y-0' : 'translate-y-full'}
        `}
      >
        <Ticket
          className="w-full h-full flex flex-col"
          onClose={handleTicketClose} 
          currentOrder={currentOrder} 
          editingTicket={editingTicket}
          savedTickets={savedTickets} 
          settings={settings} 
          total={total} 
          subtotal={subtotal} 
          tax={tax}
          editingQuantityItemId={editingQuantityItemId} 
          tempQuantity={tempQuantity} 
          setEditingQuantityItemId={setEditingQuantityItemId}
          setTempQuantity={setTempQuantity} 
          removeFromOrder={removeFromOrder} 
          deleteLineItem={deleteLineItem}
          updateOrderItemQuantity={updateOrderItemQuantity}
          handleQuantityClick={handleQuantityClick} 
          handleQuantityChangeCommit={handleQuantityChangeCommit}
          handleQuantityInputChange={handleQuantityInputChange}
          handleQuantityInputKeyDown={handleQuantityInputKeyDown}
          handlePrimarySaveAction={handlePrimarySaveAction}
          onCharge={handleChargeClick} 
          onOpenTickets={handleOpenTicketsClick}
          onSaveTicket={handleSaveTicketClick} 
          printers={printers}
          onClearTicket={handleClearTicket}
          onPrintRequest={handlePrintRequest}
        />
      </div>

      {/* Modals */}
      <SaveTicketModal isOpen={isSaveModalOpen} onClose={() => { setIsSaveModalOpen(false); setPendingPrintAction(false); }} onSave={handleSaveTicketComplete} editingTicket={editingTicket} />
      <OpenTicketsModal isOpen={isOpenTicketsModalOpen} tickets={savedTickets} onClose={() => setIsOpenTicketsModalOpen(false)} onLoadTicket={handleLoadTicket} onDeleteTicket={handleDeleteTicket} />
      <SelectItemModal isOpen={isSelectItemModalOpen} onClose={() => setIsSelectItemModalOpen(false)} onSelect={handleSelectItem} allItems={items} />
      <ManageGridsModal isOpen={isManageGridsModalOpen} onClose={() => setIsManageGridsModalOpen(false)} initialGrids={customGrids} onSave={handleSaveGrids} />
      <AddGridModal isOpen={isAddGridModalOpen} onClose={() => setIsAddGridModalOpen(false)} onSave={handleSaveNewGrid} />

      <ConfirmModal
        isOpen={confirmModalState.isOpen}
        onClose={() => setConfirmModalState(prev => ({ ...prev, isOpen: false }))}
        onConfirm={() => {
            confirmModalState.onConfirm();
            setConfirmModalState(prev => ({ ...prev, isOpen: false }));
        }}
        title={confirmModalState.title}
        confirmText={confirmModalState.confirmText}
        confirmButtonClass={confirmModalState.confirmButtonClass}
      >
        {confirmModalState.message}
      </ConfirmModal>
    </div>
  );
};

export default SalesScreen;

import React, { useState, useRef, useEffect } from 'react';
import { MenuIcon, SearchIcon, CloseIcon } from '../../constants';

interface SalesHeaderProps {
  openDrawer: () => void;
  searchQuery: string;
  onSearchChange: (query: string) => void;
}

const SalesHeader: React.FC<SalesHeaderProps> = ({ openDrawer, searchQuery, onSearchChange }) => {
  const [isSearching, setIsSearching] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  // Automatically enter search mode if there is a query (e.g. restored from state)
  useEffect(() => {
      if (searchQuery && !isSearching) {
          setIsSearching(true);
      }
  }, [searchQuery]);

  // Focus input when entering search mode
  useEffect(() => {
      if (isSearching && inputRef.current) {
          inputRef.current.focus();
      }
  }, [isSearching]);

  const handleQueryChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    onSearchChange(e.target.value);
  };

  const handleClearText = () => {
    onSearchChange('');
    // Keep focus on input after clearing
    inputRef.current?.focus();
  };

  const handleCloseSearch = () => {
    setIsSearching(false);
    onSearchChange('');
  };

  return (
    <header className="bg-surface shadow-sm border-b border-border w-full z-10 flex-shrink-0 h-16 pt-safe-top box-content flex items-center justify-between px-4 transition-all">
      {isSearching ? (
        <div className="flex items-center w-full gap-3 animate-fadeIn">
          <div className="relative flex-grow">
            <SearchIcon className="absolute left-3 top-1/2 transform -translate-y-1/2 text-text-muted h-5 w-5 pointer-events-none" />
            <input
              ref={inputRef}
              type="text"
              placeholder="Search item name..."
              value={searchQuery}
              onChange={handleQueryChange}
              className="w-full h-11 pl-10 pr-10 bg-surface-muted rounded-xl border-transparent focus:bg-background focus:border-primary focus:ring-2 focus:ring-primary/20 transition-all text-text-primary placeholder:text-text-muted"
            />
            {searchQuery && (
                <button 
                    onClick={handleClearText}
                    className="absolute right-2 top-1/2 transform -translate-y-1/2 p-1 text-text-muted hover:text-text-primary bg-surface border border-border rounded-full hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors"
                    aria-label="Clear text"
                >
                    <CloseIcon className="h-3 w-3" />
                </button>
            )}
          </div>
          <button
            onClick={handleCloseSearch}
            className="px-3 py-2 text-text-secondary hover:text-text-primary font-semibold text-sm rounded-lg hover:bg-surface-muted transition-colors"
          >
            Cancel
          </button>
        </div>
      ) : (
        <div className="flex items-center justify-between w-full">
          <div className="flex items-center gap-3">
             <button onClick={openDrawer} className="p-2 -ml-2 text-text-secondary hover:text-text-primary rounded-full hover:bg-surface-muted transition-colors">
                <MenuIcon className="h-6 w-6" />
             </button>
             <h1 className="text-xl font-bold text-text-primary tracking-tight">
               Sales
             </h1>
          </div>
          <button onClick={() => setIsSearching(true)} className="p-2.5 text-text-secondary hover:text-primary bg-surface-muted hover:bg-primary/10 rounded-xl transition-all">
            <SearchIcon className="h-5 w-5" />
          </button>
        </div>
      )}
    </header>
  );
};

export default SalesHeader;

import React, { useMemo, useState, useRef, useEffect } from 'react';
import { OrderItem, SavedTicket } from '../../types';
import { ThreeDotsIcon, TrashIcon, ArrowLeftIcon } from '../../constants';

// --- Helper Component: Swipeable Item Row ---
interface SwipeableOrderItemProps {
    item: OrderItem;
    editingQuantityItemId: string | null;
    tempQuantity: string;
    onQuantityClick: (item: OrderItem) => void;
    onQuantityChange: (e: React.ChangeEvent<HTMLInputElement>) => void;
    onQuantityCommit: () => void;
    onQuantityKeyDown: (e: React.KeyboardEvent<HTMLInputElement>) => void;
    onIncrement: (id: string, qty: number) => void;
    onDecrement: (id: string) => void;
    onDelete: (id: string) => void;
}

const SwipeableOrderItem = React.memo<SwipeableOrderItemProps>(({
    item, editingQuantityItemId, tempQuantity,
    onQuantityClick, onQuantityChange, onQuantityCommit, onQuantityKeyDown,
    onIncrement, onDecrement, onDelete
}) => {
    const [offset, setOffset] = useState(0);
    const [isSwiping, setIsSwiping] = useState(false);
    const startX = useRef(0);
    const currentOffset = useRef(0);
    const isOpen = offset < -60; // Threshold to consider "open"

    // Handlers for Touch
    const handleTouchStart = (e: React.TouchEvent | React.MouseEvent) => {
        // Don't start swipe if editing quantity
        if (editingQuantityItemId === item.lineItemId) return;

        setIsSwiping(true);
        const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
        startX.current = clientX;
        currentOffset.current = offset;
    };

    const handleTouchMove = (e: React.TouchEvent | React.MouseEvent) => {
        if (!isSwiping) return;
        const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
        const diff = clientX - startX.current;

        let newOffset = currentOffset.current + diff;
        if (newOffset > 0) newOffset = 0; 
        if (newOffset < -100) newOffset = -100; 

        setOffset(newOffset);
    };

    const handleTouchEnd = () => {
        setIsSwiping(false);
        // Snap logic
        if (offset < -40) {
            setOffset(-80); // Snap open (reveal width)
        } else {
            setOffset(0); // Snap closed
        }
    };

    const handleContentClick = () => {
        if (isOpen) setOffset(0);
    };

    return (
        <li className="relative border-b border-black/5 dark:border-white/10 overflow-hidden select-none transform translate-z-0 last:border-0">
            {/* Background Action Layer (Delete) */}
            <div className="absolute inset-0 flex justify-end bg-red-600">
                <button
                    onClick={() => onDelete(item.lineItemId)}
                    className="w-[80px] h-full flex flex-col items-center justify-center text-white active:bg-red-700 transition-colors"
                >
                    <TrashIcon className="h-6 w-6 mb-1" />
                    <span className="text-[10px] font-bold uppercase tracking-wider">Delete</span>
                </button>
            </div>

            {/* Foreground Content Layer */}
            <div 
                className="relative bg-surface flex items-center justify-between pl-4 pr-4 py-3 transition-transform duration-200 ease-out"
                style={{ transform: `translateX(${offset}px)` }}
                onTouchStart={handleTouchStart}
                onTouchMove={handleTouchMove}
                onTouchEnd={handleTouchEnd}
                onMouseDown={handleTouchStart}
                onMouseMove={handleTouchMove}
                onMouseUp={handleTouchEnd}
                onMouseLeave={handleTouchEnd}
                onClick={handleContentClick}
            >
                {/* Left Side: Item Name */}
                <div className="flex-grow min-w-0 pr-3 pointer-events-none">
                    <p className="font-medium text-text-primary text-sm whitespace-normal break-words leading-tight">{item.name}</p>
                </div>

                {/* Right Side: Controls and Price */}
                <div className="flex items-center gap-3 flex-shrink-0">
                    {/* Quantity Controls */}
                    <div className="flex items-center gap-1 bg-surface-muted/50 rounded-lg p-0.5" onMouseDown={e => e.stopPropagation()} onTouchStart={e => e.stopPropagation()}>
                        <button 
                            onClick={() => onDecrement(item.lineItemId)} 
                            className="h-7 w-7 flex items-center justify-center text-text-secondary hover:bg-white dark:hover:bg-black/20 rounded shadow-sm transition-all focus:outline-none" 
                            aria-label="Decrease quantity"
                        >
                            <span className="text-lg leading-none mb-0.5">-</span>
                        </button>

                        {editingQuantityItemId === item.lineItemId ? (
                            <input 
                                type="tel" 
                                value={tempQuantity} 
                                onChange={onQuantityChange} 
                                onBlur={onQuantityCommit} 
                                onKeyDown={onQuantityKeyDown} 
                                className="font-mono w-10 text-center text-base font-bold text-text-primary bg-background border border-primary rounded ring-1 ring-primary/20 py-0.5 mx-0.5" 
                                autoFocus 
                                onFocus={(e) => e.target.select()} 
                            />
                        ) : (
                            <button
                                onClick={() => onQuantityClick(item)} 
                                className="font-mono min-w-[28px] text-center text-base font-bold text-text-primary cursor-pointer active:scale-95 transition-transform py-0.5 mx-0.5"
                            >
                                {item.quantity}
                            </button>
                        )}

                        <button 
                            onClick={() => onIncrement(item.lineItemId, item.quantity + 1)} 
                            className="h-7 w-7 flex items-center justify-center text-text-secondary hover:bg-white dark:hover:bg-black/20 rounded shadow-sm transition-all focus:outline-none" 
                            aria-label="Increase quantity"
                        >
                             <span className="text-lg leading-none mb-0.5">+</span>
                        </button>
                    </div>

                    {/* Total Price */}
                    <div className="w-[70px] text-right pointer-events-none">
                        <p className="font-bold text-text-primary text-base">₹{(item.price * item.quantity).toFixed(0)}</p>
                    </div>
                </div>
            </div>
        </li>
    );
});


interface TicketProps {
    className?: string;
    onClose?: () => void;
    // Data
    currentOrder: OrderItem[];
    editingTicket: SavedTicket | null;
    savedTickets: SavedTicket[];
    settings: { taxEnabled: boolean; taxRate: number };
    total: number;
    subtotal: number;
    tax: number;
    printers: any[];

    // State & Handlers
    editingQuantityItemId: string | null;
    tempQuantity: string;
    setEditingQuantityItemId: (id: string | null) => void;
    setTempQuantity: (qty: string) => void;
    removeFromOrder: (lineItemId: string) => void;
    deleteLineItem: (lineItemId: string) => void;
    updateOrderItemQuantity: (lineItemId: string, newQuantity: number) => void;
    handleQuantityClick: (item: OrderItem) => void;
    handleQuantityChangeCommit: () => void;
    handleQuantityInputChange: (e: React.ChangeEvent<HTMLInputElement>) => void;
    handleQuantityInputKeyDown: (e: React.KeyboardEvent<HTMLInputElement>) => void;

    // Main Actions
    handlePrimarySaveAction: () => void;
    onCharge: () => void;
    onOpenTickets: () => void;
    onSaveTicket: () => void;
    onClearTicket: () => void;
    onPrintRequest: () => void;
}

const Ticket: React.FC<TicketProps> = (props) => {
  const {
    className, onClose,
    currentOrder, editingTicket, savedTickets, settings, total, subtotal, tax, printers,
    editingQuantityItemId, tempQuantity, setEditingQuantityItemId, setTempQuantity, 
    removeFromOrder, deleteLineItem, updateOrderItemQuantity,
    handleQuantityClick, handleQuantityChangeCommit, handleQuantityInputChange, handleQuantityInputKeyDown,
    handlePrimarySaveAction, onCharge, onOpenTickets, onSaveTicket, onClearTicket, onPrintRequest
  } = props;

  const [isTicketMenuOpen, setTicketMenuOpen] = useState(false);
  const [isClearConfirmVisible, setIsClearConfirmVisible] = useState(false);
  const ticketMenuRef = useRef<HTMLDivElement>(null);
  const listContainerRef = useRef<HTMLDivElement>(null);

  // Also trigger when order length changes (item added)
  useEffect(() => {
     if (listContainerRef.current) {
         requestAnimationFrame(() => {
             // Use 'auto' instead of 'smooth' for instant feedback and less jitter perception
             listContainerRef.current?.scrollTo({ top: listContainerRef.current.scrollHeight, behavior: 'auto' });
         });
     }
  }, [currentOrder.length]);


  useEffect(() => {
    // Use 'click' instead of 'mousedown' for better reliability on touch devices/hybrid apps
    const handleClickOutside = (event: MouseEvent | TouchEvent) => {
        if (ticketMenuRef.current && !ticketMenuRef.current.contains(event.target as Node)) {
            setTicketMenuOpen(false);
        }
    };

    // Using click handles both mouse and touch tap emulation effectively in most React envs
    document.addEventListener("click", handleClickOutside);
    return () => document.removeEventListener("click", handleClickOutside);
  }, []);

  useEffect(() => {
    if (isClearConfirmVisible) {
        setTicketMenuOpen(false);
    }
  }, [isClearConfirmVisible]);


  const handleTicketAction = async (action: string) => {
    setTicketMenuOpen(false);
    switch (action) {
      case 'clear':
        if (currentOrder.length === 0 && !editingTicket) return;
        setIsClearConfirmVisible(true);
        break;

      case 'print':
        if (currentOrder.length === 0) {
           alert("Ticket is empty. Nothing to print.");
           return;
        }
        onPrintRequest();
        break;

      case 'edit':
        if (currentOrder.length === 0 && !editingTicket) {
           alert("No ticket to edit.");
           return;
        }
        onSaveTicket();
        break;
      default:
        break;
    }
  };

  const handleConfirmClear = () => {
    onClearTicket();
    setIsClearConfirmVisible(false);
  };

  const renderActionButtons = () => {
    if (currentOrder.length > 0) {
      return (
        <button 
          onClick={handlePrimarySaveAction}
          className="flex-1 bg-surface border-2 border-primary text-primary font-bold py-3.5 rounded-xl transition-all text-base shadow-sm hover:bg-primary/5 active:scale-[0.98] active:bg-primary/10"
        >
          {editingTicket ? 'Update Order' : 'Save Order'}
        </button>
      );
    }
    if (savedTickets.length > 0) {
      return (
        // Text is allowed to wrap to new lines. Flex layout ensures siblings stretch to same height.
        <button 
          onClick={onOpenTickets}
          className="flex-1 bg-amber-500 text-white font-bold py-3 rounded-xl transition-all text-sm shadow-md hover:bg-amber-600 active:scale-[0.98] px-2 leading-tight break-words flex flex-col justify-center items-center"
        >
          <span>Open Tickets</span>
          <span className="text-xs">({savedTickets.length})</span>
        </button>
      );
    }
    return (
      <button 
        disabled
        className="flex-1 bg-surface-muted text-text-muted font-bold py-3.5 rounded-xl text-base cursor-not-allowed border border-transparent"
      >
        Save Order
      </button>
    );
  };

  const ticketHeaderTitle = useMemo(() => {
    if (editingTicket) return editingTicket.name;
    if (currentOrder.length > 0) return 'Current Order';
    return 'New Order';
  }, [editingTicket, currentOrder.length]);

  return (
    <section className={`${className} bg-surface border-l border-border h-full flex flex-col pt-safe-top relative`}>
      <header className="bg-surface shadow-sm w-full z-30 flex-shrink-0 h-16 flex items-center justify-between px-4 border-b border-border">
        <div className="flex items-center gap-3 overflow-hidden">
            {onClose && (
                <button 
                  onClick={onClose} 
                  className="md:hidden p-2 -ml-2 text-text-secondary active:text-text-primary rounded-full hover:bg-surface-muted transition-colors"
                >
                    <ArrowLeftIcon className="h-6 w-6" />
                </button>
            )}
            <div className="flex flex-col min-w-0">
                <h1 className="text-lg font-bold text-text-primary truncate leading-tight">{ticketHeaderTitle}</h1>
                {currentOrder.length > 0 && (
                    <span className="text-xs text-text-secondary">{currentOrder.reduce((acc, i) => acc + i.quantity, 0)} items</span>
                )}
            </div>
        </div>
        <div className="relative" ref={ticketMenuRef}>
            <button 
              onClick={(e) => { e.stopPropagation(); setTicketMenuOpen(prev => !prev); }} 
              className="p-2 text-text-secondary hover:text-text-primary rounded-full hover:bg-surface-muted transition-colors active:bg-surface-muted" 
              aria-label="Ticket options"
            >
              <ThreeDotsIcon className="h-6 w-6" />
            </button>
            {isTicketMenuOpen && (
                <div
                    className="absolute right-0 mt-2 w-56 bg-surface rounded-xl shadow-xl ring-1 ring-black ring-opacity-5 dark:ring-white/10 z-50 overflow-hidden"
                >
                    <div className="py-1">
                        <button onClick={() => handleTicketAction('clear')} className="w-full text-left px-4 py-3 text-sm font-medium text-red-600 hover:bg-red-50 dark:hover:bg-red-900/10 transition-colors">Clear Ticket</button>
                        <button onClick={() => handleTicketAction('print')} className="w-full text-left px-4 py-3 text-sm font-medium text-text-primary hover:bg-surface-muted transition-colors">
                          Print Bill (Preview)
                        </button>
                        <button onClick={() => handleTicketAction('edit')} className="w-full text-left px-4 py-3 text-sm font-medium text-text-primary hover:bg-surface-muted transition-colors">Edit Ticket Details</button>
                    </div>
                </div>
            )}
          </div>
      </header>

      {/* Scrollable Area: Items + Sticky Totals */}
      <div 
        ref={listContainerRef} 
        className="flex-1 overflow-y-auto flex flex-col relative min-h-0 bg-surface-muted/30"
        style={{ 
            WebkitOverflowScrolling: 'touch',
            transform: 'translateZ(0)', // Fix for painting glitches on iOS/Mobile when toggling display
        }}
      >
          {currentOrder.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-full text-text-muted opacity-60">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-16 w-16 mb-4 stroke-1" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeLinecap="round" strokeLinejoin="round"><path d="M6 2L3 6v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2V6l-3-4Z" /><path d="M3 6h18" /><path d="M16 10a4 4 0 0 1-8 0" /></svg>
              <p className="font-medium text-lg">Your cart is empty</p>
              <p className="text-sm mt-1">Tap items to start an order</p>
            </div>
          ) : (
            <>
                <div className="bg-surface shadow-sm">
                    <ul className="overflow-x-hidden">
                    {currentOrder.map(item => (
                        <SwipeableOrderItem
                            key={item.lineItemId}
                            item={item}
                            editingQuantityItemId={editingQuantityItemId}
                            tempQuantity={tempQuantity}
                            onQuantityClick={handleQuantityClick}
                            onQuantityChange={handleQuantityInputChange}
                            onQuantityCommit={handleQuantityChangeCommit}
                            onQuantityKeyDown={handleQuantityInputKeyDown}
                            onIncrement={updateOrderItemQuantity}
                            onDecrement={removeFromOrder}
                            onDelete={deleteLineItem}
                        />
                    ))}
                    </ul>
                </div>

                {/* --- Sticky Totals Section --- */}
                <div className="sticky bottom-0 bg-surface border-t border-border z-10 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)] mt-auto">
                    <div className="px-5 py-3">
                        <div className="border-b border-black/5 dark:border-white/10 mb-2"></div>
                        {settings.taxEnabled && (
                            <div className="space-y-1 text-xs text-text-secondary mb-2">
                                <div className="flex justify-between"><span>Subtotal</span><span>₹{subtotal.toFixed(2)}</span></div>
                                <div className="flex justify-between"><span>GST ({settings.taxRate}%)</span><span>₹{tax.toFixed(2)}</span></div>
                            </div>
                        )}
                        <div className="flex justify-between items-baseline pt-1">
                            <span className="text-sm font-semibold text-text-secondary">Total Payable</span>
                            <span className="text-2xl font-bold text-text-primary">₹{total.toFixed(2)}</span>
                        </div>
                    </div>
                </div>
            </>
          )}
      </div>

      {/* Absolute Overlay for Clear Confirmation to prevent layout glitch */}
      {isClearConfirmVisible && (
        <div className="absolute inset-0 z-40 bg-surface flex flex-col items-center justify-center p-6 animate-fadeIn">
            <div className="bg-red-100 dark:bg-red-900/30 p-4 rounded-full mb-4">
                <TrashIcon className="h-8 w-8 text-red-600 dark:text-red-400" />
            </div>
            <h3 className="text-xl font-bold text-text-primary mb-2">Clear Current Order?</h3>
            <p className="text-sm text-text-secondary mb-8 max-w-[200px] text-center">All items will be removed. This cannot be undone.</p>
            <div className="flex gap-3 w-full max-w-xs">
                <button onClick={() => setIsClearConfirmVisible(false)} className="flex-1 py-3 bg-surface border border-border text-text-primary rounded-xl hover:bg-gray-100 dark:hover:bg-gray-700 font-semibold transition-colors">
                    Cancel
                </button>
                <button onClick={handleConfirmClear} className="flex-1 py-3 bg-red-600 text-white font-semibold rounded-xl hover:bg-red-700 shadow-md transition-colors">
                    Clear All
                </button>
            </div>
        </div>
      )}

      {/* Fixed Bottom Area for Buttons */}
      <div className="bg-surface border-t border-border z-20 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)]">
        <div className="p-4 pt-3 pb-safe-bottom">
            <div className={`flex items-stretch gap-3 ${isClearConfirmVisible ? 'opacity-0 pointer-events-none' : ''}`}>
                {renderActionButtons()}
                <button 
                    onClick={onCharge} 
                    disabled={currentOrder.length === 0} 
                    className="flex-[1.5] bg-emerald-600 text-white font-bold py-3.5 rounded-xl transition-all text-lg shadow-md hover:bg-emerald-700 active:scale-[0.98] active:shadow-sm disabled:bg-gray-300 disabled:dark:bg-gray-700 disabled:text-gray-500 disabled:cursor-not-allowed disabled:shadow-none flex justify-center items-center"
                >
                Charge
                </button>
            </div>
        </div>
      </div>
    </section>
  );
};

export default Ticket;

import React, { useState, useRef, useEffect } from 'react';
import { MenuIcon, SearchIcon, CloseIcon } from '../../constants';

interface SalesHeaderProps {
  openDrawer: () => void;
  searchQuery: string;
  onSearchChange: (query: string) => void;
}

const SalesHeader: React.FC<SalesHeaderProps> = ({ openDrawer, searchQuery, onSearchChange }) => {
  const [isSearching, setIsSearching] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  // Automatically enter search mode if there is a query (e.g. restored from state)
  useEffect(() => {
      if (searchQuery && !isSearching) {
          setIsSearching(true);
      }
  }, [searchQuery]);

  // Focus input when entering search mode
  useEffect(() => {
      if (isSearching && inputRef.current) {
          inputRef.current.focus();
      }
  }, [isSearching]);

  const handleQueryChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    onSearchChange(e.target.value);
  };

  const handleClearText = () => {
    onSearchChange('');
    // Keep focus on input after clearing
    inputRef.current?.focus();
  };

  const handleCloseSearch = () => {
    setIsSearching(false);
    onSearchChange('');
  };

  return (
    // Outer container handles background and Safe Area padding (Status Bar)
    <header className="bg-surface shadow-sm border-b border-border w-full z-10 flex-shrink-0 pt-safe-top transition-all">
      {/* Inner container handles actual App Bar height and content alignment */}
      <div className="h-14 flex items-center justify-between px-4 w-full">
        {isSearching ? (
          <div className="flex items-center w-full gap-3 animate-fadeIn">
            <div className="relative flex-grow">
              <SearchIcon className="absolute left-3 top-1/2 transform -translate-y-1/2 text-text-muted h-4 w-4 pointer-events-none" />
              <input
                ref={inputRef}
                type="text"
                placeholder="Search..."
                value={searchQuery}
                onChange={handleQueryChange}
                className="w-full h-10 pl-9 pr-9 bg-surface-muted rounded-full border-transparent focus:bg-background focus:border-primary focus:ring-2 focus:ring-primary/20 transition-all text-sm text-text-primary placeholder:text-text-muted"
              />
              {searchQuery && (
                  <button 
                      onClick={handleClearText}
                      className="absolute right-2 top-1/2 transform -translate-y-1/2 p-1 text-text-muted hover:text-text-primary bg-surface border border-border rounded-full hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors"
                      aria-label="Clear text"
                  >
                      <CloseIcon className="h-3 w-3" />
                  </button>
              )}
            </div>
            <button
              onClick={handleCloseSearch}
              className="whitespace-nowrap px-3 py-1.5 text-text-secondary hover:text-text-primary font-semibold text-sm rounded-lg hover:bg-surface-muted transition-colors"
            >
              Cancel
            </button>
          </div>
        ) : (
          <div className="flex items-center justify-between w-full">
            <div className="flex items-center gap-3">
               <button onClick={openDrawer} className="p-2 -ml-2 text-text-secondary hover:text-text-primary rounded-full hover:bg-surface-muted transition-colors">
                  <MenuIcon className="h-6 w-6" />
               </button>
               <h1 className="text-lg font-bold text-text-primary tracking-tight">
                 Restaurant POS
               </h1>
            </div>
            <button onClick={() => setIsSearching(true)} className="p-2 text-text-secondary hover:text-primary bg-surface-muted/50 hover:bg-primary/10 rounded-full transition-all">
              <SearchIcon className="h-5 w-5" />
            </button>
          </div>
        )}
      </div>
    </header>
  );
};

export default SalesHeader;

import React, { useMemo, useState, useRef, useEffect } from 'react';
import { OrderItem, SavedTicket } from '../../types';
import { ThreeDotsIcon, TrashIcon, ArrowLeftIcon } from '../../constants';

// --- Helper Component: Swipeable Item Row ---
interface SwipeableOrderItemProps {
    item: OrderItem;
    editingQuantityItemId: string | null;
    tempQuantity: string;
    onQuantityClick: (item: OrderItem) => void;
    onQuantityChange: (e: React.ChangeEvent<HTMLInputElement>) => void;
    onQuantityCommit: () => void;
    onQuantityKeyDown: (e: React.KeyboardEvent<HTMLInputElement>) => void;
    onIncrement: (id: string, qty: number) => void;
    onDecrement: (id: string) => void;
    onDelete: (id: string) => void;
}

const SwipeableOrderItem = React.memo<SwipeableOrderItemProps>(({
    item, editingQuantityItemId, tempQuantity,
    onQuantityClick, onQuantityChange, onQuantityCommit, onQuantityKeyDown,
    onIncrement, onDecrement, onDelete
}) => {
    const [offset, setOffset] = useState(0);
    const [isSwiping, setIsSwiping] = useState(false);
    const startX = useRef(0);
    const currentOffset = useRef(0);
    const isOpen = offset < -60; // Threshold to consider "open"

    // Handlers for Touch
    const handleTouchStart = (e: React.TouchEvent | React.MouseEvent) => {
        // Don't start swipe if editing quantity
        if (editingQuantityItemId === item.lineItemId) return;

        setIsSwiping(true);
        const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
        startX.current = clientX;
        currentOffset.current = offset;
    };

    const handleTouchMove = (e: React.TouchEvent | React.MouseEvent) => {
        if (!isSwiping) return;
        const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
        const diff = clientX - startX.current;

        let newOffset = currentOffset.current + diff;
        if (newOffset > 0) newOffset = 0; 
        if (newOffset < -100) newOffset = -100; 

        setOffset(newOffset);
    };

    const handleTouchEnd = () => {
        setIsSwiping(false);
        // Snap logic
        if (offset < -40) {
            setOffset(-80); // Snap open (reveal width)
        } else {
            setOffset(0); // Snap closed
        }
    };

    const handleContentClick = () => {
        if (isOpen) setOffset(0);
    };

    return (
        <li className="relative border-b border-black/5 dark:border-white/10 overflow-hidden select-none transform translate-z-0 last:border-0">
            {/* Background Action Layer (Delete) */}
            <div className="absolute inset-0 flex justify-end bg-red-600">
                <button
                    onClick={() => onDelete(item.lineItemId)}
                    className="w-[80px] h-full flex flex-col items-center justify-center text-white active:bg-red-700 transition-colors"
                >
                    <TrashIcon className="h-6 w-6 mb-1" />
                    <span className="text-[10px] font-bold uppercase tracking-wider">Delete</span>
                </button>
            </div>

            {/* Foreground Content Layer */}
            <div 
                className="relative bg-surface flex items-center justify-between pl-4 pr-4 py-3 transition-transform duration-200 ease-out"
                style={{ transform: `translateX(${offset}px)` }}
                onTouchStart={handleTouchStart}
                onTouchMove={handleTouchMove}
                onTouchEnd={handleTouchEnd}
                onMouseDown={handleTouchStart}
                onMouseMove={handleTouchMove}
                onMouseUp={handleTouchEnd}
                onMouseLeave={handleTouchEnd}
                onClick={handleContentClick}
            >
                {/* Left Side: Item Name */}
                <div className="flex-grow min-w-0 pr-3 pointer-events-none">
                    <p className="font-medium text-text-primary text-sm whitespace-normal break-words leading-tight">{item.name}</p>
                </div>

                {/* Right Side: Controls and Price */}
                <div className="flex items-center gap-3 flex-shrink-0">
                    {/* Quantity Controls */}
                    <div className="flex items-center gap-1 bg-surface-muted/50 rounded-lg p-0.5" onMouseDown={e => e.stopPropagation()} onTouchStart={e => e.stopPropagation()}>
                        <button 
                            onClick={() => onDecrement(item.lineItemId)} 
                            className="h-7 w-7 flex items-center justify-center text-text-secondary hover:bg-white dark:hover:bg-black/20 rounded shadow-sm transition-all focus:outline-none" 
                            aria-label="Decrease quantity"
                        >
                            <span className="text-lg leading-none mb-0.5">-</span>
                        </button>

                        {editingQuantityItemId === item.lineItemId ? (
                            <input 
                                type="tel" 
                                value={tempQuantity} 
                                onChange={onQuantityChange} 
                                onBlur={onQuantityCommit} 
                                onKeyDown={onQuantityKeyDown} 
                                className="font-mono w-10 text-center text-base font-bold text-text-primary bg-background border border-primary rounded ring-1 ring-primary/20 py-0.5 mx-0.5" 
                                autoFocus 
                                onFocus={(e) => e.target.select()} 
                            />
                        ) : (
                            <button
                                onClick={() => onQuantityClick(item)} 
                                className="font-mono min-w-[28px] text-center text-base font-bold text-text-primary cursor-pointer active:scale-95 transition-transform py-0.5 mx-0.5"
                            >
                                {item.quantity}
                            </button>
                        )}

                        <button 
                            onClick={() => onIncrement(item.lineItemId, item.quantity + 1)} 
                            className="h-7 w-7 flex items-center justify-center text-text-secondary hover:bg-white dark:hover:bg-black/20 rounded shadow-sm transition-all focus:outline-none" 
                            aria-label="Increase quantity"
                        >
                             <span className="text-lg leading-none mb-0.5">+</span>
                        </button>
                    </div>

                    {/* Total Price */}
                    <div className="w-[70px] text-right pointer-events-none">
                        <p className="font-bold text-text-primary text-base">₹{(item.price * item.quantity).toFixed(0)}</p>
                    </div>
                </div>
            </div>
        </li>
    );
});


interface TicketProps {
    className?: string;
    onClose?: () => void;
    // Data
    currentOrder: OrderItem[];
    editingTicket: SavedTicket | null;
    savedTickets: SavedTicket[];
    settings: { taxEnabled: boolean; taxRate: number };
    total: number;
    subtotal: number;
    tax: number;
    printers: any[];

    // State & Handlers
    editingQuantityItemId: string | null;
    tempQuantity: string;
    setEditingQuantityItemId: (id: string | null) => void;
    setTempQuantity: (qty: string) => void;
    removeFromOrder: (lineItemId: string) => void;
    deleteLineItem: (lineItemId: string) => void;
    updateOrderItemQuantity: (lineItemId: string, newQuantity: number) => void;
    handleQuantityClick: (item: OrderItem) => void;
    handleQuantityChangeCommit: () => void;
    handleQuantityInputChange: (e: React.ChangeEvent<HTMLInputElement>) => void;
    handleQuantityInputKeyDown: (e: React.KeyboardEvent<HTMLInputElement>) => void;

    // Main Actions
    handlePrimarySaveAction: () => void;
    onCharge: () => void;
    onOpenTickets: () => void;
    onSaveTicket: () => void;
    onClearTicket: () => void;
    onPrintRequest: () => void;
}

const Ticket: React.FC<TicketProps> = (props) => {
  const {
    className, onClose,
    currentOrder, editingTicket, savedTickets, settings, total, subtotal, tax, printers,
    editingQuantityItemId, tempQuantity, setEditingQuantityItemId, setTempQuantity, 
    removeFromOrder, deleteLineItem, updateOrderItemQuantity,
    handleQuantityClick, handleQuantityChangeCommit, handleQuantityInputChange, handleQuantityInputKeyDown,
    handlePrimarySaveAction, onCharge, onOpenTickets, onSaveTicket, onClearTicket, onPrintRequest
  } = props;

  const [isTicketMenuOpen, setTicketMenuOpen] = useState(false);
  const [isClearConfirmVisible, setIsClearConfirmVisible] = useState(false);
  const ticketMenuRef = useRef<HTMLDivElement>(null);
  const listContainerRef = useRef<HTMLDivElement>(null);

  // Also trigger when order length changes (item added)
  useEffect(() => {
     if (listContainerRef.current) {
         requestAnimationFrame(() => {
             // Use 'auto' instead of 'smooth' for instant feedback and less jitter perception
             listContainerRef.current?.scrollTo({ top: listContainerRef.current.scrollHeight, behavior: 'auto' });
         });
     }
  }, [currentOrder.length]);


  useEffect(() => {
    // Use 'click' instead of 'mousedown' for better reliability on touch devices/hybrid apps
    const handleClickOutside = (event: MouseEvent | TouchEvent) => {
        if (ticketMenuRef.current && !ticketMenuRef.current.contains(event.target as Node)) {
            setTicketMenuOpen(false);
        }
    };

    // Using click handles both mouse and touch tap emulation effectively in most React envs
    document.addEventListener("click", handleClickOutside);
    return () => document.removeEventListener("click", handleClickOutside);
  }, []);

  useEffect(() => {
    if (isClearConfirmVisible) {
        setTicketMenuOpen(false);
    }
  }, [isClearConfirmVisible]);


  const handleTicketAction = async (action: string) => {
    setTicketMenuOpen(false);
    switch (action) {
      case 'clear':
        if (currentOrder.length === 0 && !editingTicket) return;
        setIsClearConfirmVisible(true);
        break;

      case 'print':
        if (currentOrder.length === 0) {
           alert("Ticket is empty. Nothing to print.");
           return;
        }
        onPrintRequest();
        break;

      case 'edit':
        if (currentOrder.length === 0 && !editingTicket) {
           alert("No ticket to edit.");
           return;
        }
        onSaveTicket();
        break;
      default:
        break;
    }
  };

  const handleConfirmClear = () => {
    onClearTicket();
    setIsClearConfirmVisible(false);
  };

  const renderActionButtons = () => {
    if (currentOrder.length > 0) {
      return (
        <button 
          onClick={handlePrimarySaveAction}
          className="flex-1 bg-surface border-2 border-primary text-primary font-bold py-3.5 rounded-xl transition-all text-base shadow-sm hover:bg-primary/5 active:scale-[0.98] active:bg-primary/10"
        >
          {editingTicket ? 'Update Order' : 'Save Order'}
        </button>
      );
    }
    if (savedTickets.length > 0) {
      return (
        // Text is allowed to wrap to new lines. Flex layout ensures siblings stretch to same height.
        <button 
          onClick={onOpenTickets}
          className="flex-1 bg-amber-500 text-white font-bold py-3 rounded-xl transition-all text-sm shadow-md hover:bg-amber-600 active:scale-[0.98] px-2 leading-tight break-words flex flex-col justify-center items-center"
        >
          <span>Open Tickets</span>
          <span className="text-xs">({savedTickets.length})</span>
        </button>
      );
    }
    return (
      <button 
        disabled
        className="flex-1 bg-surface-muted text-text-muted font-bold py-3.5 rounded-xl text-base cursor-not-allowed border border-transparent"
      >
        Save Order
      </button>
    );
  };

  const ticketHeaderTitle = useMemo(() => {
    if (editingTicket) return editingTicket.name;
    if (currentOrder.length > 0) return 'Current Order';
    return 'New Order';
  }, [editingTicket, currentOrder.length]);

  return (
    // Added pt-safe-top to outer container, remove fixed height from header, use inner container
    <section className={`${className} bg-surface border-l border-border h-full flex flex-col pt-safe-top relative`}>
      <header className="bg-surface shadow-sm w-full z-30 flex-shrink-0 border-b border-border">
        <div className="h-14 flex items-center justify-between px-4">
            <div className="flex items-center gap-3 overflow-hidden">
                {onClose && (
                    <button 
                    onClick={onClose} 
                    className="md:hidden p-2 -ml-2 text-text-secondary active:text-text-primary rounded-full hover:bg-surface-muted transition-colors"
                    >
                        <ArrowLeftIcon className="h-6 w-6" />
                    </button>
                )}
                <div className="flex flex-col min-w-0">
                    <h1 className="text-lg font-bold text-text-primary truncate leading-tight">{ticketHeaderTitle}</h1>
                    {currentOrder.length > 0 && (
                        <span className="text-xs text-text-secondary">{currentOrder.reduce((acc, i) => acc + i.quantity, 0)} items</span>
                    )}
                </div>
            </div>
            <div className="relative" ref={ticketMenuRef}>
                <button 
                onClick={(e) => { e.stopPropagation(); setTicketMenuOpen(prev => !prev); }} 
                className="p-2 text-text-secondary hover:text-text-primary rounded-full hover:bg-surface-muted transition-colors active:bg-surface-muted" 
                aria-label="Ticket options"
                >
                <ThreeDotsIcon className="h-6 w-6" />
                </button>
                {isTicketMenuOpen && (
                    <div
                        className="absolute right-0 mt-2 w-56 bg-surface rounded-xl shadow-xl ring-1 ring-black ring-opacity-5 dark:ring-white/10 z-50 overflow-hidden"
                    >
                        <div className="py-1">
                            <button onClick={() => handleTicketAction('clear')} className="w-full text-left px-4 py-3 text-sm font-medium text-red-600 hover:bg-red-50 dark:hover:bg-red-900/10 transition-colors">Clear Ticket</button>
                            <button onClick={() => handleTicketAction('print')} className="w-full text-left px-4 py-3 text-sm font-medium text-text-primary hover:bg-surface-muted transition-colors">
                            Print Bill (Preview)
                            </button>
                            <button onClick={() => handleTicketAction('edit')} className="w-full text-left px-4 py-3 text-sm font-medium text-text-primary hover:bg-surface-muted transition-colors">Edit Ticket Details</button>
                        </div>
                    </div>
                )}
            </div>
        </div>
      </header>

      {/* Scrollable Area: Items + Sticky Totals */}
      <div 
        ref={listContainerRef} 
        className="flex-1 overflow-y-auto flex flex-col relative min-h-0 bg-surface-muted/30"
        style={{ 
            WebkitOverflowScrolling: 'touch',
            transform: 'translateZ(0)', // Fix for painting glitches on iOS/Mobile when toggling display
        }}
      >
          {currentOrder.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-full text-text-muted opacity-60">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-16 w-16 mb-4 stroke-1" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeLinecap="round" strokeLinejoin="round"><path d="M6 2L3 6v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2V6l-3-4Z" /><path d="M3 6h18" /><path d="M16 10a4 4 0 0 1-8 0" /></svg>
              <p className="font-medium text-lg">Your cart is empty</p>
              <p className="text-sm mt-1">Tap items to start an order</p>
            </div>
          ) : (
            <>
                <div className="bg-surface shadow-sm">
                    <ul className="overflow-x-hidden">
                    {currentOrder.map(item => (
                        <SwipeableOrderItem
                            key={item.lineItemId}
                            item={item}
                            editingQuantityItemId={editingQuantityItemId}
                            tempQuantity={tempQuantity}
                            onQuantityClick={handleQuantityClick}
                            onQuantityChange={handleQuantityInputChange}
                            onQuantityCommit={handleQuantityChangeCommit}
                            onQuantityKeyDown={handleQuantityInputKeyDown}
                            onIncrement={updateOrderItemQuantity}
                            onDecrement={removeFromOrder}
                            onDelete={deleteLineItem}
                        />
                    ))}
                    </ul>
                </div>

                {/* --- Sticky Totals Section --- */}
                <div className="sticky bottom-0 bg-surface border-t border-border z-10 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)] mt-auto">
                    <div className="px-5 py-3">
                        <div className="border-b border-black/5 dark:border-white/10 mb-2"></div>
                        {settings.taxEnabled && (
                            <div className="space-y-1 text-xs text-text-secondary mb-2">
                                <div className="flex justify-between"><span>Subtotal</span><span>₹{subtotal.toFixed(2)}</span></div>
                                <div className="flex justify-between"><span>GST ({settings.taxRate}%)</span><span>₹{tax.toFixed(2)}</span></div>
                            </div>
                        )}
                        <div className="flex justify-between items-baseline pt-1">
                            <span className="text-sm font-semibold text-text-secondary">Total Payable</span>
                            <span className="text-2xl font-bold text-text-primary">₹{total.toFixed(2)}</span>
                        </div>
                    </div>
                </div>
            </>
          )}
      </div>

      {/* Absolute Overlay for Clear Confirmation to prevent layout glitch */}
      {isClearConfirmVisible && (
        <div className="absolute inset-0 z-40 bg-surface flex flex-col items-center justify-center p-6 animate-fadeIn">
            <div className="bg-red-100 dark:bg-red-900/30 p-4 rounded-full mb-4">
                <TrashIcon className="h-8 w-8 text-red-600 dark:text-red-400" />
            </div>
            <h3 className="text-xl font-bold text-text-primary mb-2">Clear Current Order?</h3>
            <p className="text-sm text-text-secondary mb-8 max-w-[200px] text-center">All items will be removed. This cannot be undone.</p>
            <div className="flex gap-3 w-full max-w-xs">
                <button onClick={() => setIsClearConfirmVisible(false)} className="flex-1 py-3 bg-surface border border-border text-text-primary rounded-xl hover:bg-gray-100 dark:hover:bg-gray-700 font-semibold transition-colors">
                    Cancel
                </button>
                <button onClick={handleConfirmClear} className="flex-1 py-3 bg-red-600 text-white font-semibold rounded-xl hover:bg-red-700 shadow-md transition-colors">
                    Clear All
                </button>
            </div>
        </div>
      )}

      {/* Fixed Bottom Area for Buttons */}
      <div className="bg-surface border-t border-border z-20 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)]">
        <div className="p-4 pt-3 pb-safe-bottom">
            <div className={`flex items-stretch gap-3 ${isClearConfirmVisible ? 'opacity-0 pointer-events-none' : ''}`}>
                {renderActionButtons()}
                <button 
                    onClick={onCharge} 
                    disabled={currentOrder.length === 0} 
                    className="flex-[1.5] bg-emerald-600 text-white font-bold py-3.5 rounded-xl transition-all text-lg shadow-md hover:bg-emerald-700 active:scale-[0.98] active:shadow-sm disabled:bg-gray-300 disabled:dark:bg-gray-700 disabled:text-gray-500 disabled:cursor-not-allowed disabled:shadow-none flex justify-center items-center"
                >
                Charge
                </button>
            </div>
        </div>
      </div>
    </section>
  );
};

export default Ticket;

import React from 'react';
import { PlusIcon } from '../../constants';
import { Item } from '../../types';
import ItemTile from './ItemTile';

interface ItemGridProps {
  itemsForDisplay: (Item | null)[];
  mode: 'all' | 'grid';
  onAddItemToOrder: (item: Item) => void;
  onAssignItem: (slotIndex: number) => void;
  onRemoveItem?: (slotIndex: number) => void;
  loadMoreRef?: React.RefObject<HTMLDivElement>;
  isEditing?: boolean;
}

const ItemGrid = React.memo<ItemGridProps>(({ 
    itemsForDisplay, mode, onAddItemToOrder, onAssignItem, onRemoveItem, 
    loadMoreRef, isEditing = false 
}) => {
  const isFixedGrid = mode === 'grid';

  // Fix: Use simple grid classes without forcing height or rows.
  // This prevents the "stretched" look and allows tiles to maintain aspect ratio.
  const gridClasses = 'grid grid-cols-3 md:grid-cols-5 gap-2 md:gap-3 pb-20 md:pb-0';

  return (
    <div>
      <div className={gridClasses}>
        {itemsForDisplay.map((item, index) => {
          if (!item) {
            // Only allow assigning items to empty slots if we are in 'grid' mode.
            if (mode === 'all') return null;

            return (
              <button
                type="button"
                key={`placeholder-${index}`}
                onClick={() => {
                    if (isEditing) onAssignItem(index);
                }}
                disabled={!isEditing}
                className={`w-full rounded-xl border-2 border-dashed border-border 
                           flex items-center justify-center text-text-muted transition-colors 
                           aspect-square
                           ${isEditing ? 'cursor-pointer hover:bg-surface-muted hover:border-primary hover:text-primary bg-surface-muted/20' : 'opacity-50 cursor-default'}`}
              >
                {isEditing && <PlusIcon className="h-8 w-8" />}
              </button>
            );
          }

          return (
            <ItemTile
                key={`${item.id}-${index}`}
                item={item}
                mode={mode}
                onAddItemToOrder={onAddItemToOrder}
                onAssignItem={onAssignItem}
                onRemoveFromGrid={onRemoveItem}
                index={index}
                isFixedGrid={isFixedGrid}
                isEditing={isEditing}
            />
          );
        })}
      </div>
      {/* Sentinel for infinite scrolling */}
      {loadMoreRef && itemsForDisplay.length > 0 && (
          <div ref={loadMoreRef} className="h-20 w-full flex items-center justify-center mt-4">
              <div className="w-2 h-2 bg-surface-muted rounded-full"></div>
          </div>
      )}
    </div>
  );
});

export default ItemGrid;

import React from 'react';
import { Item } from '../../types';
import { TrashIcon, PencilIcon } from '../../constants';

interface ItemTileProps {
    item: Item;
    mode: 'all' | 'grid';
    onAddItemToOrder: (item: Item) => void;
    onAssignItem: (slotIndex: number) => void;
    onRemoveFromGrid?: (slotIndex: number) => void;
    index: number;
    isFixedGrid: boolean;
    isEditing: boolean;
}

const ItemTile: React.FC<ItemTileProps> = React.memo(({ 
    item, mode, onAddItemToOrder, onAssignItem, onRemoveFromGrid, 
    index, isFixedGrid, isEditing 
}) => {

    const hasRealImage = item.imageUrl && !item.imageUrl.includes('via.placeholder.com');

    // --- EDIT MODE RENDER ---
    if (isEditing && mode === 'grid') {
        return (
            <div 
                className={`relative w-full rounded-xl overflow-hidden border-2 border-dashed border-primary/60 bg-primary/5 aspect-square animate-pulse`}
            >
                {/* Background Image (Dimmed) */}
                {hasRealImage && (
                    <img 
                        src={item.imageUrl} 
                        alt={item.name} 
                        className="absolute inset-0 w-full h-full object-cover z-0 opacity-30 grayscale pointer-events-none"
                    />
                )}

                {/* Center: Tap to Swap/Edit */}
                <button
                    type="button"
                    onClick={() => onAssignItem(index)}
                    className="absolute inset-0 flex flex-col items-center justify-center z-10 w-full h-full touch-manipulation"
                >
                    <div className="bg-primary/10 p-2 rounded-full mb-1">
                        <PencilIcon className="h-6 w-6 text-primary" />
                    </div>
                    <span className="text-[10px] uppercase font-bold text-primary bg-surface/90 px-2 py-0.5 rounded-full shadow-sm">Change</span>
                </button>

                {/* Top Right: Delete Button */}
                <button 
                    type="button"
                    onClick={(e) => {
                        e.stopPropagation();
                        if(onRemoveFromGrid) onRemoveFromGrid(index);
                    }}
                    className="absolute top-1 right-1 z-20 bg-red-500 text-white rounded-full p-1.5 shadow-md hover:bg-red-600 active:scale-90 transition-transform touch-manipulation"
                >
                    <TrashIcon className="h-4 w-4" />
                </button>

                {/* Bottom Label */}
                <div className="absolute bottom-0 left-0 right-0 p-1.5 bg-black/50 backdrop-blur-sm z-0 pointer-events-none">
                    <h3 className="font-semibold text-white text-xs text-center truncate">
                        {item.name}
                    </h3>
                </div>
            </div>
        );
    }

    // --- NORMAL MODE RENDER (SPEED OPTIMIZED) ---

    const handleClick = (e: React.MouseEvent<HTMLButtonElement>) => {
        onAddItemToOrder(item);
    };

    // Price Badge Component
    const PriceBadge = () => (
        <div className="absolute top-1 right-1 md:top-2 md:right-2 bg-black/60 text-white backdrop-blur-sm px-1.5 py-0.5 md:px-2 md:py-1 rounded-md text-[10px] md:text-xs font-bold shadow-lg z-10 tabular-nums tracking-tight border border-white/20 pointer-events-none">
            ₹{item.price.toFixed(0)}
        </div>
    );

    if (hasRealImage) {
        return (
            <button
                type="button"
                onClick={handleClick}
                // Enforce aspect-square to prevent stretching/squashing
                className={`relative w-full rounded-xl overflow-hidden cursor-pointer shadow-sm border border-border/50 bg-surface-muted group aspect-square touch-manipulation select-none`}
                aria-label={`Add ${item.name} to order`}
            >
                <div className="w-full h-full pointer-events-none relative">
                    <img 
                        src={item.imageUrl} 
                        alt={item.name} 
                        className="absolute inset-0 w-full h-full object-cover z-0"
                        loading="lazy"
                        decoding="async"
                    />

                    {/* Active State Overlay */}
                    <div className="absolute inset-0 bg-black opacity-0 group-active:opacity-20 z-30 transition-none"></div>

                    <PriceBadge />

                    {/* Gradient Overlay */}
                    <div className="absolute inset-x-0 bottom-0 h-1/2 bg-gradient-to-t from-black/80 via-black/40 to-transparent z-10"></div>

                    <div className="absolute bottom-0 left-0 right-0 p-2 z-20">
                        {/* Mobile: text-xs, line-clamp-2. Tablet: slightly larger. */}
                        <h3 className="font-bold text-white text-xs md:text-sm leading-tight text-center line-clamp-2 drop-shadow-sm">
                            {item.name}
                        </h3>
                    </div>
                </div>
            </button>
        );
    } else {
        return (
            <button
                type="button"
                onClick={handleClick}
                // Enforce aspect-square
                className={`relative w-full rounded-xl cursor-pointer shadow-sm border border-border bg-surface group aspect-square touch-manipulation select-none hover:border-primary/50`}
                aria-label={`Add ${item.name} to order`}
            >
                {/* Active Overlay */}
                <div className="absolute inset-0 bg-primary opacity-0 group-active:opacity-10 z-10 rounded-xl transition-none"></div>

                <PriceBadge />
                <div className="w-full h-full flex flex-col justify-center items-center p-2 md:p-3 text-center pointer-events-none relative z-0">
                     <div className="w-6 h-1 md:w-8 bg-primary/20 rounded-full mb-2 md:mb-3"></div>
                    {/* Mobile: text-xs. Tablet: text-base. */}
                    <h3 className="font-bold text-text-primary text-xs md:text-base leading-snug line-clamp-3">
                        {item.name}
                    </h3>
                </div>
            </button>
        );
    }
});

