            </div>
            <button onClick={() => setIsSearching(true)} className="p-2 text-text-secondary hover:text-primary bg-surface-muted/50 hover:bg-primary/10 rounded-full transition-all">
              <SearchIcon className="h-5 w-5" />
            </button>
          </div>
