                                            className={`px-3 py-1.5 text-xs font-semibold rounded-md capitalize transition-all ${shiftFilter === s ? 'bg-surface text-primary shadow-sm' : 'text-text-muted hover:text-text-primary'}`}
                                        >
                                            {s === 'all' ? 'All Day' : s}
                                        </button>
                                    ))}
                                </div>
                            )}

                            {isFilterActive && (
