/**
 * PRINTER HELPER
 * 
 * Required Plugins for Native Device functionality:
 * 
 * 1. Bluetooth Serial (for printing)
 *    > npm install cordova-plugin-bluetooth-serial
 * 
 * 2. Android Permissions (for Android 12+ Bluetooth scan permissions)
 *    > npm install cordova-plugin-android-permissions
 * 
 * After installing, run:
 *    > npx cap sync
 */

import { AppSettings, OrderItem, Printer } from '../types';
import { requestAppPermissions } from './permissions';

declare global {
  interface Window {
    bluetoothSerial: any;
  }
}

// Basic ESC/POS Commands
const ESC = '\x1b';
const GS = '\x1d';
const COMMANDS = {
  INIT: ESC + '@',
  CENTER: ESC + 'a' + '\x01',
  LEFT: ESC + 'a' + '\x00',
  RIGHT: ESC + 'a' + '\x02',
  BOLD_ON: ESC + 'E' + '\x01',
  BOLD_OFF: ESC + 'E' + '\x00',
  CUT: GS + 'V' + '\x41' + '\x00',

  // Font Sizing (ESC ! n)
  // n = 0 (Normal)
  // n = 16 (Double Height)
  // n = 32 (Double Width)
  // n = 48 (Double Width + Double Height)
  TXT_NORMAL: ESC + '!' + '\x00',
  TXT_2HEIGHT: ESC + '!' + '\x10',
  TXT_2WIDTH: ESC + '!' + '\x20',
  TXT_4SQUARE: ESC + '!' + '\x30', 
};

/**
 * Connects to a specific Bluetooth device.
 */
const connectToPrinter = (address: string): Promise<void> => {
  return new Promise((resolve, reject) => {
    window.bluetoothSerial.connect(
      address,
      () => {
        console.log("Printer Connected:", address);
        resolve();
      },
      (err: any) => {
        console.error("Connection failed:", err);
        reject(new Error(`Could not connect to printer. Please ensure it is turned on and in range.`));
      }
    );
  });
};

/**
 * Disconnects from the currently connected device.
 */
const disconnectFromPrinter = (): Promise<void> => {
    return new Promise((resolve) => {
        if (window.bluetoothSerial) {
            window.bluetoothSerial.disconnect(
                () => {
                    console.log("Printer Disconnected.");
                    resolve();
                },
                () => {
                    console.warn("Failed to disconnect, or was not connected.");
                    resolve(); 
                }
            );
        } else {
            resolve();
        }
    });
};

/**
 * Checks if Bluetooth is enabled on the device.
 */
const checkBluetoothEnabled = (): Promise<void> => {
  return new Promise((resolve, reject) => {
    if (!window.bluetoothSerial) {
        // If plugin is missing (web), assume enabled/simulated
        resolve();
        return;
    }
    window.bluetoothSerial.isEnabled(
      () => resolve(),
      () => reject(new Error("Bluetooth is disabled. Please enable it in Settings."))
    );
  });
};

/**
 * Creates a smart row with Left and Right alignment.
 * Automatically truncates the Left text if it overlaps with the Right text.
 * Puts at least 1 space between them.
 */
const createRow = (left: string, right: string, width: number): string => {
    const minSpace = 1;
    const maxLeftLen = width - right.length - minSpace;

    let cleanLeft = left;
    if (cleanLeft.length > maxLeftLen) {
        cleanLeft = cleanLeft.substring(0, maxLeftLen - 1) + '.';
    }

    const spaceCount = width - cleanLeft.length - right.length;
    return cleanLeft + ' '.repeat(Math.max(0, spaceCount)) + right + '\n';
};

const createDivider = (width: number): string => '-'.repeat(width) + '\n';

const formatCurrency = (amount: number) => amount.toFixed(2);

/**
 * Consolidates multiple lines of the same item into a single line with summed quantity.
 */
const consolidateItems = (items: OrderItem[]): OrderItem[] => {
    const consolidated = new Map<string, OrderItem>();
    items.forEach(item => {
        const existing = consolidated.get(item.id);
        if (existing) {
            consolidated.set(item.id, { ...existing, quantity: existing.quantity + item.quantity });
        } else {
            consolidated.set(item.id, { ...item }); 
        }
    });
    return Array.from(consolidated.values());
};


interface PrintBillArgs {
  items: OrderItem[];
  total: number;
  subtotal: number;
  tax: number;
  ticketName?: string;
  settings: AppSettings;
  printer?: Printer;
}

export interface PrintReceiptArgs extends PrintBillArgs {
    receiptId: string;
    paymentMethod: string;
    date: Date;
}

const sendToPrinter = async (data: string, printer: Printer): Promise<{ success: boolean; message: string }> => {
    // Web Fallback
    if (!window.bluetoothSerial) {
        console.log("--- SIMULATED PRINT ---");
        console.log(data.replace(/[\x1b\x1d]/g, '')); 
        //alert(`Simulated Print to ${printer.name}`);
        return { success: true, message: "Simulated print successful" };
    }

    // Native Logic
    if (printer.interfaceType !== 'Bluetooth' || !printer.address) {
        return { success: false, message: "Only Bluetooth printers with a valid MAC address are supported." };
    }

    try {
        // 1. Check Permissions
        const hasPermission = await requestAppPermissions();
        if (!hasPermission) return { success: false, message: "Bluetooth permissions denied." };

        // 2. Check Enabled Status (Prevent Crash)
        await checkBluetoothEnabled();

        // 3. Connect
        await connectToPrinter(printer.address);

        // 4. Write
        await new Promise<void>((resolve, reject) => {
            window.bluetoothSerial.write(data, 
                () => resolve(), 
                (err: any) => {
                    console.error("Bluetooth write failed:", err);
                    const message = typeof err === 'string' ? err : (err?.message || 'Unknown write error');
                    reject(new Error(message));
                }
            );
        });

        return { success: true, message: "Data sent to printer." };
    } catch (error: any) {
        return { success: false, message: error.message || "An unknown printing error occurred." };
    } finally {
        await disconnectFromPrinter();
    }
}


export const testPrint = async (printer: Printer, settings?: AppSettings): Promise<{ success: boolean; message: string }> => {
    let data = COMMANDS.INIT;
    data += COMMANDS.TXT_2WIDTH;
    data += COMMANDS.CENTER + COMMANDS.BOLD_ON + "TEST PRINT\n" + COMMANDS.BOLD_OFF + COMMANDS.TXT_NORMAL;
    data += "If you can read this,\nprinter is configured.\n";
    data += "\n\n" + COMMANDS.CUT;
    return sendToPrinter(data, printer);
};

export const printBill = async (args: PrintBillArgs): Promise<{ success: boolean; message: string }> => {
    const { items, total, settings, printer, ticketName } = args;

    if (!printer) {
      return { success: false, message: "No printer configured." };
    }

    // Config
    const width = printer.paperWidth === '80mm' ? 48 : 32;
    const consolidatedItems = consolidateItems(items);

    const newLine = '\n\n';

    // 1. Init & Header
    let data = COMMANDS.INIT + COMMANDS.CENTER;

    if(settings.storeName) {
        const safeName = settings.storeName.replace(/[\r\n]+/g, ' ').trim().toUpperCase();
        data += COMMANDS.TXT_2WIDTH;
        data += COMMANDS.BOLD_ON + safeName + '\n' + COMMANDS.BOLD_OFF + COMMANDS.TXT_NORMAL;
    }
    data += "ESTIMATE / BILL\n";

    if (ticketName) {
        data += `Ticket: ${ticketName}\n`;
    }

    data += COMMANDS.LEFT;
    data += createDivider(width);

    // 2. Items (Compact Format)
    consolidatedItems.forEach(item => {
        const lineTotal = formatCurrency(item.price * item.quantity);
        // Format: "50 x 2 Burger ............ 100.00"
        const leftText = `${item.price.toFixed(0)} x ${item.quantity} ${item.name}`;
        data += createRow(leftText, lineTotal, width);
    });
    data += createDivider(width);

    // 3. Totals
    data += COMMANDS.CENTER + COMMANDS.BOLD_ON + COMMANDS.TXT_4SQUARE;
    data += "TOTAL: " + formatCurrency(total);
    data += COMMANDS.TXT_NORMAL + COMMANDS.BOLD_OFF + "\n";

    data += newLine + COMMANDS.CUT;

    return sendToPrinter(data, printer);
};

export const printReceipt = async (args: PrintReceiptArgs): Promise<{ success: boolean; message: string }> => {
    const { items, total, subtotal, tax, receiptId, paymentMethod, settings, printer, date } = args;

    if (!printer) {
      return { success: false, message: "No printer configured." };
    }

    const width = printer.paperWidth === '80mm' ? 48 : 32;
    const consolidatedItems = consolidateItems(items);
    const receiptDate = date; // Use the provided date
    const dateStr = receiptDate.toLocaleDateString();
    const timeStr = receiptDate.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'});
    const newLine = '\n\n';

    // 1. Init & Header
    let data = COMMANDS.INIT + COMMANDS.CENTER;

    if (settings.storeName) {
        const safeName = settings.storeName.replace(/[\r\n]+/g, ' ').trim().toUpperCase();
        data += COMMANDS.TXT_2WIDTH;
        data += COMMANDS.BOLD_ON + safeName + '\n' + COMMANDS.BOLD_OFF + COMMANDS.TXT_NORMAL;
    }

    if (settings.storeAddress) {
        const safeAddr = settings.storeAddress.replace(/[\r\n]+/g, ' ').trim();
        data += safeAddr + '\n';
    }

    data += '\n'; // Spacer

    // 2. Meta
    data += COMMANDS.LEFT;

    const metaLeft = `${dateStr} ${timeStr}`;
    const metaRight = `#${receiptId.slice(-4)}`;
    data += createRow(metaLeft, metaRight, width);

    data += createDivider(width);

    // 3. Items
    consolidatedItems.forEach(item => {
        const lineTotal = formatCurrency(item.price * item.quantity);
        // Format: "50 x 2 Burger ............ 100.00"
        const leftText = `${item.price.toFixed(0)} x ${item.quantity} ${item.name}`;
        data += createRow(leftText, lineTotal, width);
    });
    data += createDivider(width);

    // 4. Totals
    if (settings.taxEnabled) {
         data += createRow('Subtotal', formatCurrency(subtotal), width);
         data += createRow(`Tax (${settings.taxRate}%)`, formatCurrency(tax), width);
         data += createDivider(width);
    }

    data += COMMANDS.CENTER + COMMANDS.BOLD_ON + COMMANDS.TXT_4SQUARE;
    data += "TOTAL: " + formatCurrency(total) + "\n";
    data += COMMANDS.TXT_NORMAL + COMMANDS.BOLD_OFF + COMMANDS.LEFT; // Reset

    data += '\n';
    data += createRow('Paid via:', paymentMethod, width);

    // 5. Footer
    data += createDivider(width);
    data += COMMANDS.CENTER;
    if(settings.receiptFooter) {
        const safeFooter = settings.receiptFooter.replace(/[\r\n]+/g, ' ').trim();
        data += safeFooter + '\n';
    }
    data += "Thank you for visiting!\n";

    // Cut command usually needs a few line feeds to push paper out
    data += newLine + COMMANDS.CUT;

    return sendToPrinter(data, printer);
};

import React, { useState, useEffect, useRef } from 'react';
import { NavLink, useNavigate, useLocation } from 'react-router-dom';
import { useAppContext } from '../context/AppContext';
import { useStatusContext } from '../context/StatusContext';
import { NAV_LINKS, SignOutIcon, SyncIcon, OfflineIcon, CheckIcon, UserIcon, PowerIcon } from '../constants';
import ConfirmModal from './modals/ConfirmModal';
import { App } from '@capacitor/app';
import { Capacitor } from '@capacitor/core';
import { Haptics, ImpactStyle } from '@capacitor/haptics';

const NavDrawer: React.FC = () => {
  const { isDrawerOpen, closeDrawer, user, signOut, settings, currentOrder } = useAppContext();
  const { pendingSyncCount, isOnline } = useStatusContext();
  const [isSignOutModalOpen, setIsSignOutModalOpen] = useState(false);
  const [isExitModalOpen, setIsExitModalOpen] = useState(false);

  const navigate = useNavigate();
  const location = useLocation();

  // State Ref for Back Button Listener Closure
  const stateRef = useRef({ 
      isDrawerOpen, 
      isExitModalOpen, 
      pathname: location.pathname,
      hasCartItems: currentOrder.length > 0 
  });

  useEffect(() => {
      stateRef.current = { 
          isDrawerOpen, 
          isExitModalOpen, 
          pathname: location.pathname,
          hasCartItems: currentOrder.length > 0
      };
  }, [isDrawerOpen, isExitModalOpen, location.pathname, currentOrder.length]);

  // Hardware Back Button Handler
  useEffect(() => {
      if (!Capacitor.isNativePlatform()) return;

      const setupListener = async () => {
          await App.addListener('backButton', ({ canGoBack }) => {
              const { isDrawerOpen, isExitModalOpen, pathname, hasCartItems } = stateRef.current;

              // Priority 1: Close Drawer
              if (isDrawerOpen) {
                  closeDrawer();
                  return;
              } 

              // Priority 2: Close Exit Modal
              if (isExitModalOpen) {
                  setIsExitModalOpen(false);
                  return;
              } 

              // Priority 3: Check for "Open Modals" in the DOM
              // This is a safety catch for modals that don't have their own back-button logic
              const openModals = document.querySelectorAll('.fixed.inset-0.z-50');
              if (openModals.length > 0) {
                  // Simulate an escape key or click backdrop of the topmost modal
                  const closeBtn = openModals[openModals.length - 1].querySelector('button[aria-label="Close"], button:contains("Cancel"), button:contains("Close")');
                  if (closeBtn instanceof HTMLElement) {
                      closeBtn.click();
                  }
                  return;
              }

              // Priority 4: Standard Navigation
              if (pathname !== '/sales') {
                  navigate(-1);
              } else {
                  // On Home Screen (Sales)
                  if (hasCartItems) {
                      // If there are items in cart, maybe don't exit immediately? 
                      // For now, standard behavior is show exit prompt
                      setIsExitModalOpen(true);
                  } else {
                      setIsExitModalOpen(true);
                  }
              }
          });
      };

      setupListener();

      return () => {
          App.removeAllListeners();
      };
  }, [closeDrawer, navigate]);

  const handleSignOutClick = async () => {
    await Haptics.impact({ style: ImpactStyle.Light });
    closeDrawer();
    setIsSignOutModalOpen(true);
  };

  const confirmSignOut = () => {
    signOut();
    setIsSignOutModalOpen(false);
  };

  const handleExitClick = async () => {
    await Haptics.impact({ style: ImpactStyle.Medium });
    closeDrawer();
    setIsExitModalOpen(true);
  };

  const confirmExit = async () => {
    if (Capacitor.isNativePlatform()) {
        await App.exitApp();
    } else {
        window.close();
    }
    setIsExitModalOpen(false);
  };

  const handleNavClick = async () => {
      await Haptics.impact({ style: ImpactStyle.Light });
      closeDrawer();
  };

  return (
    <>
      <div
        onClick={closeDrawer}
        className={`fixed inset-0 bg-black/60 backdrop-blur-sm z-[60] transition-opacity duration-300 ease-out ${
          isDrawerOpen ? 'opacity-100 pointer-events-auto' : 'opacity-0 pointer-events-none'
        }`}
        aria-hidden="true"
      />

      <aside
        className={`fixed top-0 left-0 bottom-0 w-[85vw] max-w-[320px] bg-neutral-900 text-white z-[70] flex flex-col shadow-2xl transform transition-transform duration-300 ease-out will-change-transform border-r border-neutral-800 ${
          isDrawerOpen ? 'translate-x-0' : '-translate-x-full'
        }`}
        style={{ backfaceVisibility: 'hidden' }}
      >
        <div className="p-6 border-b border-neutral-800 bg-neutral-900 pt-safe-top">
          <h2 className="text-xl font-bold text-white truncate tracking-tight">
            {settings.storeName || 'POS Menu'}
          </h2>
          <p className="text-xs text-neutral-500 mt-1 uppercase tracking-wider font-semibold">Point of Sale</p>
        </div>

        <nav className="flex-1 py-4 px-3 overflow-y-auto">
          <ul className="space-y-1">
            {NAV_LINKS.map(({ path, label, Icon }) => (
              <li key={path}>
                <NavLink
                  to={path}
                  onClick={handleNavClick}
                  className={({ isActive }) =>
                    `flex items-center px-4 py-3 text-sm font-medium rounded-full transition-all duration-200 group ${
                      isActive
                        ? 'bg-primary text-primary-content shadow-lg shadow-primary/20'
                        : 'text-neutral-400 hover:bg-neutral-800 hover:text-white'
                    }`
                  }
                >
                  <Icon className="h-5 w-5 mr-3" />
                  <span>{label}</span>
                </NavLink>
              </li>
            ))}
          </ul>
        </nav>

        <div className="px-4 py-2 mt-auto">
            <div className={`flex items-center gap-3 text-xs font-medium px-4 py-3 rounded-xl border ${
                !isOnline 
                  ? 'bg-neutral-800 border-neutral-700 text-neutral-400' 
                  : pendingSyncCount > 0 
                    ? 'bg-amber-900/20 border-amber-900/30 text-amber-400' 
                    : 'bg-emerald-900/20 border-emerald-900/30 text-emerald-400'
            }`}>
                {!isOnline ? (
                    <>
                        <OfflineIcon className="h-4 w-4 flex-shrink-0" />
                        <span>Offline Mode</span>
                    </>
                ) : pendingSyncCount > 0 ? (
                    <>
                        <SyncIcon className="h-4 w-4 animate-spin flex-shrink-0" />
                        <span>Syncing {pendingSyncCount} items...</span>
                    </>
                ) : (
                    <>
                        <CheckIcon className="h-4 w-4 flex-shrink-0" />
                        <span>System Synced</span>
                    </>
                )}
            </div>
        </div>

        <div className="p-4 border-t border-neutral-800 bg-neutral-900 pb-safe-bottom">
            <div className="flex items-center gap-3 mb-3 px-2">
                <div className="h-8 w-8 rounded-full bg-neutral-800 flex items-center justify-center text-neutral-400">
                     <UserIcon className="h-4 w-4" />
                </div>
                <div className="min-w-0">
                    <p className="text-sm font-medium text-white truncate">{user?.email}</p>
                    <p className="text-xs text-neutral-500">Administrator</p>
                </div>
            </div>

            <div className="grid grid-cols-2 gap-2">
                <button 
                    onClick={handleSignOutClick}
                    className="flex items-center justify-center px-3 py-2 text-sm font-medium transition-colors duration-200 text-neutral-400 hover:bg-neutral-800 hover:text-white rounded-lg border border-transparent"
                >
                    <SignOutIcon className="h-4 w-4 mr-2"/>
                    <span>Sign Out</span>
                </button>
                <button 
                    onClick={handleExitClick}
                    className="flex items-center justify-center px-3 py-2 text-sm font-medium transition-colors duration-200 text-red-400 hover:bg-red-500/10 hover:text-red-300 rounded-lg border border-transparent hover:border-red-500/20"
                >
                    <PowerIcon className="h-4 w-4 mr-2"/>
                    <span>Exit</span>
                </button>
            </div>
        </div>
      </aside>

      <ConfirmModal
        isOpen={isSignOutModalOpen}
        onClose={() => setIsSignOutModalOpen(false)}
        onConfirm={confirmSignOut}
        title="Sign Out"
        confirmText="Sign Out"
        confirmButtonClass="bg-red-600 hover:bg-red-700"
      >
        <p>Are you sure you want to sign out of your session?</p>
      </ConfirmModal>

      <ConfirmModal
        isOpen={isExitModalOpen}
        onClose={() => setIsExitModalOpen(false)}
        onConfirm={confirmExit}
        title="Exit Application"
        confirmText="Exit"
        confirmButtonClass="bg-red-600 hover:bg-red-700"
      >
        <p>Are you sure you want to close the application?</p>
      </ConfirmModal>
    </>
  );
};

export default NavDrawer;

import React from 'react';
import { Item } from '../../types';
import { TrashIcon, PencilIcon } from '../../constants';
import { Haptics, ImpactStyle } from '@capacitor/haptics';

interface ItemTileProps {
    item: Item;
    mode: 'all' | 'grid';
    onAddItemToOrder: (item: Item) => void;
    onAssignItem: (slotIndex: number) => void;
    onRemoveFromGrid?: (slotIndex: number) => void;
    index: number;
    isFixedGrid: boolean;
    isEditing: boolean;
}

const ItemTile: React.FC<ItemTileProps> = React.memo(({ 
    item, mode, onAddItemToOrder, onAssignItem, onRemoveFromGrid, 
    index, isFixedGrid, isEditing 
}) => {

    const hasRealImage = item.imageUrl && !item.imageUrl.includes('via.placeholder.com');

    const aspectRatioClass = isFixedGrid 
        ? 'aspect-square md:aspect-auto md:h-full' 
        : 'aspect-square';

    // --- EDIT MODE RENDER ---
    if (isEditing && mode === 'grid') {
        return (
            <div 
                className={`relative w-full rounded-xl overflow-hidden border-2 border-dashed border-primary/60 bg-primary/5 animate-pulse ${aspectRatioClass}`}
            >
                {hasRealImage && (
                    <img 
                        src={item.imageUrl} 
                        alt={item.name} 
                        className="absolute inset-0 w-full h-full object-cover z-0 opacity-30 grayscale pointer-events-none"
                    />
                )}

                <button
                    type="button"
                    onClick={async () => {
                        await Haptics.impact({ style: ImpactStyle.Light });
                        onAssignItem(index);
                    }}
                    className="absolute inset-0 flex flex-col items-center justify-center z-10 w-full h-full touch-manipulation"
                >
                    <div className="bg-primary/10 p-2 rounded-full mb-1">
                        <PencilIcon className="h-6 w-6 text-primary" />
                    </div>
                    <span className="text-[10px] uppercase font-bold text-primary bg-surface/90 px-2 py-0.5 rounded-full shadow-sm">Change</span>
                </button>

                <button 
                    type="button"
                    onClick={async (e) => {
                        e.stopPropagation();
                        await Haptics.notification({ type: ImpactStyle.Heavy });
                        if(onRemoveFromGrid) onRemoveFromGrid(index);
                    }}
                    className="absolute top-1 right-1 z-20 bg-red-500 text-white rounded-full p-1.5 shadow-md hover:bg-red-600 active:scale-90 transition-transform touch-manipulation"
                >
                    <TrashIcon className="h-4 w-4" />
                </button>

                <div className="absolute bottom-0 left-0 right-0 p-1.5 bg-black/50 backdrop-blur-sm z-0 pointer-events-none">
                    <h3 className="font-semibold text-white text-xs text-center truncate">
                        {item.name}
                    </h3>
                </div>
            </div>
        );
    }

    // --- NORMAL MODE RENDER ---
    const handleClick = async (e: React.MouseEvent<HTMLButtonElement>) => {
        await Haptics.impact({ style: ImpactStyle.Light });
        onAddItemToOrder(item);
    };

    const PriceBadge = () => (
        <div className="absolute top-1 right-1 md:top-2 md:right-2 bg-black/60 text-white backdrop-blur-sm px-1.5 py-0.5 md:px-2 md:py-1 rounded-md text-[10px] md:text-xs font-bold shadow-lg z-10 tabular-nums tracking-tight border border-white/20 pointer-events-none">
            ₹{item.price.toFixed(0)}
        </div>
    );

    if (hasRealImage) {
        return (
            <button
                type="button"
                onClick={handleClick}
                className={`relative w-full rounded-xl overflow-hidden cursor-pointer shadow-sm border border-border/50 bg-surface-muted group touch-manipulation select-none ${aspectRatioClass}`}
                aria-label={`Add ${item.name} to order`}
            >
                <div className="w-full h-full pointer-events-none relative">
                    <img 
                        src={item.imageUrl} 
                        alt={item.name} 
                        className="absolute inset-0 w-full h-full object-cover z-0"
                        loading="lazy"
                        decoding="async"
                    />

                    <div className="absolute inset-0 bg-black opacity-0 group-active:opacity-20 z-30 transition-none"></div>

                    <PriceBadge />

                    <div className="absolute inset-x-0 bottom-0 h-1/2 bg-gradient-to-t from-black/80 via-black/40 to-transparent z-10"></div>

                    <div className="absolute bottom-0 left-0 right-0 p-2 z-20">
                        <h3 className="font-bold text-white text-xs md:text-sm leading-tight text-center line-clamp-2 drop-shadow-sm">
                            {item.name}
                        </h3>
                    </div>
                </div>
            </button>
        );
    } else {
        return (
            <button
                type="button"
                onClick={handleClick}
                className={`relative w-full rounded-xl cursor-pointer shadow-sm border border-border bg-surface group touch-manipulation select-none hover:border-primary/50 ${aspectRatioClass}`}
                aria-label={`Add ${item.name} to order`}
            >
                <div className="absolute inset-0 bg-primary opacity-0 group-active:opacity-10 z-10 rounded-xl transition-none"></div>

                <PriceBadge />
                <div className="w-full h-full flex flex-col justify-center items-center p-2 md:p-3 text-center pointer-events-none relative z-0">
                     <div className="w-6 h-1 md:w-8 bg-primary/20 rounded-full mb-2 md:mb-3"></div>
                    <h3 className="font-bold text-text-primary text-xs md:text-base leading-snug line-clamp-3">
                        {item.name}
                    </h3>
                </div>
            </button>
        );
    }
});

