import React, { useState, useEffect } from 'react';
import type { SavedTicket } from '../../types';
import { useAppContext } from '../../context/AppContext';
import { Haptics, ImpactStyle } from '@capacitor/haptics';

interface SaveTicketModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (name: string) => void;
  editingTicket: SavedTicket | null;
}

const SaveTicketModal: React.FC<SaveTicketModalProps> = ({ isOpen, onClose, onSave, editingTicket }) => {
  const { tables } = useAppContext();
  const [name, setName] = useState('');

  useEffect(() => {
    if(isOpen) {
      setName(editingTicket?.name || '');
    }
  }, [isOpen, editingTicket]);

  const handleSave = async () => {
    if (name.trim()) {
      await Haptics.impact({ style: ImpactStyle.Medium });
      onSave(name.trim());
    }
  };

  const handleTableSelect = async (tableName: string) => {
    await Haptics.impact({ style: ImpactStyle.Medium });
    onSave(tableName);
  };

  const handleCancel = async () => {
    await Haptics.impact({ style: ImpactStyle.Light });
    onClose();
  };

  const isUpdating = !!editingTicket;

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black bg-opacity-60 flex items-center justify-center z-50" onClick={handleCancel}>
      <div className="bg-surface rounded-lg p-6 shadow-xl w-full max-w-lg" onClick={e => e.stopPropagation()}>
        <h2 className="text-2xl font-bold mb-4 text-text-primary">{isUpdating ? 'Update Ticket' : 'Save Ticket'}</h2>

        {tables.length > 0 && (
          <>
            <p className="text-sm font-medium text-text-secondary mb-2">Quick Select Table (Saves Immediately)</p>
            <div className="flex flex-col gap-2 mb-4 max-h-48 overflow-y-auto pr-2">
                {tables.map(table => (
                    <button 
                      key={table.id} 
                      onClick={() => handleTableSelect(table.name)} 
                      className="w-full text-left p-3 bg-surface-muted rounded-md text-text-secondary font-semibold hover:bg-emerald-100 dark:hover:bg-emerald-900/50 hover:text-emerald-700 dark:hover:text-emerald-300 transition-colors active:scale-[0.99]"
                    >
                        {table.name}
                    </button>
                ))}
            </div>

            <div className="flex items-center gap-4 my-4">
                <hr className="flex-grow border-border"/> <span className="text-text-muted text-sm">OR</span> <hr className="flex-grow border-border"/>
            </div>
          </>
        )}

        <label htmlFor="ticket-name" className="block text-sm font-medium text-text-secondary mb-1">Custom Ticket Name</label>
        <input
          id="ticket-name"
          type="text"
          value={name}
          onChange={(e) => setName(e.target.value)}
          placeholder="e.g., Party of 4"
          className="w-full p-2 border border-border rounded-md focus:ring-2 focus:ring-primary focus:border-primary bg-background text-text-primary"
          onKeyDown={(e) => e.key === 'Enter' && handleSave()}
          autoFocus
        />

        <div className="flex justify-end items-center pt-6 mt-2 border-t border-border gap-2">
            <button onClick={handleCancel} className="px-6 py-2 bg-surface-muted text-text-secondary rounded-lg hover:bg-gray-200 dark:hover:bg-gray-600">Cancel</button>
            <button onClick={handleSave} disabled={!name.trim()} className="px-6 py-2 bg-primary text-primary-content rounded-lg hover:bg-primary-hover disabled:bg-gray-300 disabled:dark:bg-gray-500">
                {isUpdating ? 'Update Ticket' : 'Save Ticket'}
            </button>
        </div>
      </div>
    </div>
  );
};

export default SaveTicketModal;

import React from 'react';
import { CloseIcon } from '../../constants';
import { Haptics, ImpactStyle } from '@capacitor/haptics';

interface ConfirmModalProps {
  isOpen: boolean;
  onClose: () => void;
  onConfirm: () => void;
  title: string;
  children: React.ReactNode;
  confirmText?: string;
  confirmButtonClass?: string;
}

const ConfirmModal: React.FC<ConfirmModalProps> = ({ isOpen, onClose, onConfirm, title, children, confirmText = 'Confirm', confirmButtonClass = 'bg-red-600 hover:bg-red-700' }) => {
  if (!isOpen) return null;

  const handleConfirm = async () => {
    await Haptics.impact({ style: ImpactStyle.Medium });
    onConfirm();
  };

  const handleClose = async () => {
    await Haptics.impact({ style: ImpactStyle.Light });
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black bg-opacity-60 flex items-center justify-center z-50" onClick={handleClose}>
      <div className="bg-surface rounded-lg p-6 shadow-xl w-full max-w-md" onClick={e => e.stopPropagation()}>
        <div className="flex justify-between items-center mb-4">
          <h2 className="text-xl font-bold text-text-primary">{title}</h2>
          <button onClick={handleClose} className="text-text-muted hover:text-text-primary">
              <CloseIcon className="h-5 w-5" />
          </button>
        </div>
        <div className="text-text-secondary mb-6">
          {children}
        </div>
        <div className="flex justify-end gap-3">
          <button onClick={handleClose} className="px-6 py-2 bg-surface-muted text-text-secondary rounded-lg hover:bg-gray-200 dark:hover:bg-gray-600 font-semibold">
            Cancel
          </button>
          <button onClick={handleConfirm} className={`px-6 py-2 text-white font-semibold rounded-lg shadow-md transition-colors ${confirmButtonClass}`}>
            {confirmText}
          </button>
        </div>
      </div>
    </div>
  );
};

export default ConfirmModal;

import React, { useState, useEffect } from 'react';
import { CloseIcon, CheckIcon } from '../../constants';
import { Item } from '../../types';
import { Haptics, ImpactStyle } from '@capacitor/haptics';

interface PriceInputModalProps {
  isOpen: boolean;
  onClose: () => void;
  onConfirm: (price: number) => void;
  item: Item | null;
}

const PriceInputModal: React.FC<PriceInputModalProps> = ({ isOpen, onClose, onConfirm, item }) => {
  const [value, setValue] = useState('');

  useEffect(() => {
    if (isOpen) {
      setValue('');
    }
  }, [isOpen]);

  const handlePress = async (key: string) => {
    await Haptics.impact({ style: ImpactStyle.Light });
    if (key === '.' && value.includes('.')) return;
    // Limit decimal places to 2
    if (value.includes('.') && value.split('.')[1].length >= 2) return;
    setValue(prev => prev + key);
  };

  const handleBackspace = async () => {
    await Haptics.impact({ style: ImpactStyle.Light });
    setValue(prev => prev.slice(0, -1));
  };

  const handleConfirm = async () => {
    const num = parseFloat(value);
    if (!isNaN(num) && num > 0) {
      await Haptics.impact({ style: ImpactStyle.Medium });
      onConfirm(num);
      onClose();
    }
  };

  const handleQuickAmount = async (amt: number) => {
    await Haptics.impact({ style: ImpactStyle.Medium });
    setValue(amt.toString());
  };

  const handleClose = async () => {
    await Haptics.impact({ style: ImpactStyle.Light });
    onClose();
  };

  if (!isOpen || !item) return null;

  const quickAmounts = [10, 20, 50, 100, 200, 500];
  const isValid = !!value && parseFloat(value) > 0;

  return (
    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-end md:items-center justify-center z-[100]" onClick={handleClose}>
      <div className="bg-surface w-full md:w-[400px] md:rounded-2xl rounded-t-2xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]" onClick={e => e.stopPropagation()}>

        {/* Header */}
        <div className="p-4 border-b border-border flex justify-between items-center bg-surface flex-shrink-0">
          <div>
            <p className="text-xs text-text-secondary uppercase tracking-wider font-bold">Enter Price For</p>
            <h2 className="text-xl font-bold text-text-primary truncate max-w-[250px]">{item.name}</h2>
          </div>
          <button onClick={handleClose} className="p-2 text-text-muted hover:text-text-primary bg-surface-muted rounded-full transition-colors">
            <CloseIcon className="h-6 w-6" />
          </button>
        </div>

        {/* Scrollable Content Wrapper */}
        <div className="flex-1 overflow-y-auto">

            {/* Display Area with Integrated Backspace */}
            <div className="p-6 bg-surface-muted/30 flex items-center justify-between border-b border-border/50 relative">
                <div className="flex-1 flex justify-center pl-10">
                    <div className="text-5xl font-mono font-bold text-text-primary flex items-baseline">
                        <span className="text-2xl text-text-muted mr-1">₹</span>
                        {value || '0'}
                        <span className="w-1 h-10 bg-primary animate-pulse ml-1 rounded-full"></span>
                    </div>
                </div>

                {/* Backspace Button (iOS Style) */}
                <button
                    onClick={handleBackspace}
                    className="p-3 text-text-secondary hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-full transition-colors active:scale-90"
                    aria-label="Backspace"
                >
                    <span className="text-2xl">⌫</span>
                </button>
            </div>

            {/* Quick amounts */}
            <div className="grid grid-cols-3 gap-2 p-4 pb-0">
                {quickAmounts.map(amt => (
                    <button 
                        key={amt} 
                        onClick={() => handleQuickAmount(amt)}
                        className="py-2 bg-surface-muted border border-border rounded-lg text-sm font-semibold text-text-secondary hover:bg-primary/10 hover:text-primary hover:border-primary transition-colors active:bg-primary/20"
                    >
                        ₹{amt}
                    </button>
                ))}
            </div>

            {/* Numpad with Integrated Confirm Button */}
            <div className="p-4 grid grid-cols-3 gap-3">
                {[1, 2, 3, 4, 5, 6, 7, 8, 9].map((num) => (
                    <button
                        key={num}
                        onClick={() => handlePress(num.toString())}
                        className="py-4 text-2xl font-bold bg-surface border border-border rounded-xl shadow-sm hover:bg-surface-muted active:scale-95 transition-all text-text-primary"
                    >
                        {num}
                    </button>
                ))}

                <button
                    onClick={() => handlePress('.')}
                    className="py-4 text-2xl font-bold bg-surface border border-border rounded-xl shadow-sm hover:bg-surface-muted active:scale-95 transition-all text-text-primary"
                >
                    .
                </button>

                <button
                    onClick={() => handlePress('0')}
                    className="py-4 text-2xl font-bold bg-surface border border-border rounded-xl shadow-sm hover:bg-surface-muted active:scale-95 transition-all text-text-primary"
                >
                    0
                </button>

                {/* Confirm Button inside Grid (Replaces Backspace position) */}
                <button
                    onClick={handleConfirm}
                    disabled={!isValid}
                    className={`py-4 flex items-center justify-center rounded-xl shadow-md active:scale-95 transition-all ${
                        isValid 
                        ? 'bg-primary text-primary-content hover:bg-primary-hover shadow-primary/30' 
                        : 'bg-surface-muted text-text-muted cursor-not-allowed border border-border'
                    }`}
                >
                    <CheckIcon className="h-8 w-8" />
                </button>
            </div>
        </div>
      </div>
    </div>
  );
};

export default PriceInputModal;

import React, { useMemo, useState, useRef, useEffect } from 'react';
import { OrderItem, SavedTicket } from '../../types';
import { ThreeDotsIcon, TrashIcon, ArrowLeftIcon } from '../../constants';
import { Haptics, ImpactStyle } from '@capacitor/haptics';

// --- Helper Component: Swipeable Item Row ---
interface SwipeableOrderItemProps {
    item: OrderItem;
    editingQuantityItemId: string | null;
    tempQuantity: string;
    onQuantityClick: (item: OrderItem) => void;
    onQuantityChange: (e: React.ChangeEvent<HTMLInputElement>) => void;
    onQuantityCommit: () => void;
    onQuantityKeyDown: (e: React.KeyboardEvent<HTMLInputElement>) => void;
    onIncrement: (id: string, qty: number) => void;
    onDecrement: (id: string) => void;
    onDelete: (id: string) => void;
}

const SwipeableOrderItem = React.memo<SwipeableOrderItemProps>(({
    item, editingQuantityItemId, tempQuantity,
    onQuantityClick, onQuantityChange, onQuantityCommit, onQuantityKeyDown,
    onIncrement, onDecrement, onDelete
}) => {
    const [offset, setOffset] = useState(0);
    const [isSwiping, setIsSwiping] = useState(false);
    const startX = useRef(0);
    const currentOffset = useRef(0);
    const isOpen = offset < -60; // Threshold to consider "open"

    // Handlers for Touch
    const handleTouchStart = (e: React.TouchEvent | React.MouseEvent) => {
        // Don't start swipe if editing quantity
        if (editingQuantityItemId === item.lineItemId) return;

        setIsSwiping(true);
        const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
        startX.current = clientX;
        currentOffset.current = offset;
    };

    const handleTouchMove = (e: React.TouchEvent | React.MouseEvent) => {
        if (!isSwiping) return;
        const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
        const diff = clientX - startX.current;

        let newOffset = currentOffset.current + diff;
        if (newOffset > 0) newOffset = 0; 
        if (newOffset < -100) newOffset = -100; 

        setOffset(newOffset);
    };

    const handleTouchEnd = () => {
        setIsSwiping(false);
        // Snap logic
        if (offset < -40) {
            setOffset(-80); // Snap open (reveal width)
        } else {
            setOffset(0); // Snap closed
        }
    };

    const handleContentClick = () => {
        if (isOpen) setOffset(0);
    };

    const handleDelete = async (id: string) => {
        await Haptics.impact({ style: ImpactStyle.Heavy });
        onDelete(id);
    };

    const handleIncrement = async (id: string, qty: number) => {
        await Haptics.impact({ style: ImpactStyle.Light });
        onIncrement(id, qty);
    };

    const handleDecrement = async (id: string) => {
        await Haptics.impact({ style: ImpactStyle.Light });
        onDecrement(id);
    };

    return (
        <li className="relative border-b border-black/5 dark:border-white/10 overflow-hidden select-none transform translate-z-0 last:border-0">
            {/* Background Action Layer (Delete) */}
            <div className="absolute inset-0 flex justify-end bg-red-600">
                <button
                    onClick={() => handleDelete(item.lineItemId)}
                    className="w-[80px] h-full flex flex-col items-center justify-center text-white active:bg-red-700 transition-colors"
                >
                    <TrashIcon className="h-6 w-6 mb-1" />
                    <span className="text-[10px] font-bold uppercase tracking-wider">Delete</span>
                </button>
            </div>

            {/* Foreground Content Layer */}
            <div 
                className="relative bg-surface flex items-center justify-between pl-4 pr-4 py-3 transition-transform duration-200 ease-out"
                style={{ transform: `translateX(${offset}px)` }}
                onTouchStart={handleTouchStart}
                onTouchMove={handleTouchMove}
                onTouchEnd={handleTouchEnd}
                onMouseDown={handleTouchStart}
                onMouseMove={handleTouchMove}
                onMouseUp={handleTouchEnd}
                onMouseLeave={handleTouchEnd}
                onClick={handleContentClick}
            >
                {/* Left Side: Item Name */}
                <div className="flex-grow min-w-0 pr-3 pointer-events-none">
                    <p className="font-medium text-text-primary text-sm whitespace-normal break-words leading-tight">{item.name}</p>
                </div>

                {/* Right Side: Controls and Price */}
                <div className="flex items-center gap-3 flex-shrink-0">
                    {/* Quantity Controls */}
                    <div className="flex items-center gap-1 bg-surface-muted/50 rounded-lg p-0.5" onMouseDown={e => e.stopPropagation()} onTouchStart={e => e.stopPropagation()}>
                        <button 
                            onClick={() => handleDecrement(item.lineItemId)} 
                            className="h-7 w-7 flex items-center justify-center text-text-secondary hover:bg-white dark:hover:bg-black/20 rounded shadow-sm transition-all focus:outline-none" 
                            aria-label="Decrease quantity"
                        >
                            <span className="text-lg leading-none mb-0.5">-</span>
                        </button>

                        {editingQuantityItemId === item.lineItemId ? (
                            <input 
                                type="tel" 
                                value={tempQuantity} 
                                onChange={onQuantityChange} 
                                onBlur={onQuantityCommit} 
                                onKeyDown={onQuantityKeyDown} 
                                className="font-mono w-10 text-center text-base font-bold text-text-primary bg-background border border-primary rounded ring-1 ring-primary/20 py-0.5 mx-0.5" 
                                autoFocus 
                                onFocus={(e) => e.target.select()} 
                            />
                        ) : (
                            <button
                                onClick={() => onQuantityClick(item)} 
                                className="font-mono min-w-[28px] text-center text-base font-bold text-text-primary cursor-pointer active:scale-95 transition-transform py-0.5 mx-0.5"
                            >
                                {item.quantity}
                            </button>
                        )}

                        <button 
                            onClick={() => handleIncrement(item.lineItemId, item.quantity + 1)} 
                            className="h-7 w-7 flex items-center justify-center text-text-secondary hover:bg-white dark:hover:bg-black/20 rounded shadow-sm transition-all focus:outline-none" 
                            aria-label="Increase quantity"
                        >
                             <span className="text-lg leading-none mb-0.5">+</span>
                        </button>
                    </div>

                    {/* Total Price */}
                    <div className="w-[70px] text-right pointer-events-none">
                        <p className="font-bold text-text-primary text-base">₹{(item.price * item.quantity).toFixed(0)}</p>
                    </div>
                </div>
            </div>
        </li>
    );
});


interface TicketProps {
    className?: string;
    onClose?: () => void;
    // Data
    currentOrder: OrderItem[];
    editingTicket: SavedTicket | null;
    savedTickets: SavedTicket[];
    settings: { taxEnabled: boolean; taxRate: number };
    total: number;
    subtotal: number;
    tax: number;
    printers: any[];

    // State & Handlers
    editingQuantityItemId: string | null;
    tempQuantity: string;
    setEditingQuantityItemId: (id: string | null) => void;
    setTempQuantity: (qty: string) => void;
    removeFromOrder: (lineItemId: string) => void;
    deleteLineItem: (lineItemId: string) => void;
    updateOrderItemQuantity: (lineItemId: string, newQuantity: number) => void;
    handleQuantityClick: (item: OrderItem) => void;
    handleQuantityChangeCommit: () => void;
    handleQuantityInputChange: (e: React.ChangeEvent<HTMLInputElement>) => void;
    handleQuantityInputKeyDown: (e: React.KeyboardEvent<HTMLInputElement>) => void;

    // Main Actions
    handlePrimarySaveAction: () => void;
    onCharge: () => void;
    onOpenTickets: () => void;
    onSaveTicket: () => void;
    onClearTicket: () => void;
    onPrintRequest: () => void;
}

const Ticket: React.FC<TicketProps> = (props) => {
  const {
    className, onClose,
    currentOrder, editingTicket, savedTickets, settings, total, subtotal, tax, printers,
    editingQuantityItemId, tempQuantity, setEditingQuantityItemId, setTempQuantity, 
    removeFromOrder, deleteLineItem, updateOrderItemQuantity,
    handleQuantityClick, handleQuantityChangeCommit, handleQuantityInputChange, handleQuantityInputKeyDown,
    handlePrimarySaveAction, onCharge, onOpenTickets, onSaveTicket, onClearTicket, onPrintRequest
  } = props;

  const [isTicketMenuOpen, setTicketMenuOpen] = useState(false);
  const [isClearConfirmVisible, setIsClearConfirmVisible] = useState(false);
  const ticketMenuRef = useRef<HTMLDivElement>(null);
  const listContainerRef = useRef<HTMLDivElement>(null);

  // Also trigger when order length changes (item added)
  useEffect(() => {
     if (listContainerRef.current) {
         requestAnimationFrame(() => {
             // Use 'auto' instead of 'smooth' for instant feedback and less jitter perception
             listContainerRef.current?.scrollTo({ top: listContainerRef.current.scrollHeight, behavior: 'auto' });
         });
     }
  }, [currentOrder.length]);


  useEffect(() => {
    // Use 'click' instead of 'mousedown' for better reliability on touch devices/hybrid apps
    const handleClickOutside = (event: MouseEvent | TouchEvent) => {
        if (ticketMenuRef.current && !ticketMenuRef.current.contains(event.target as Node)) {
            setTicketMenuOpen(false);
        }
    };

    // Using click handles both mouse and touch tap emulation effectively in most React envs
    document.addEventListener("click", handleClickOutside);
    return () => document.removeEventListener("click", handleClickOutside);
  }, []);

  useEffect(() => {
    if (isClearConfirmVisible) {
        setTicketMenuOpen(false);
    }
  }, [isClearConfirmVisible]);


  const handleTicketAction = async (action: string) => {
    setTicketMenuOpen(false);
    switch (action) {
      case 'clear':
        if (currentOrder.length === 0 && !editingTicket) return;
        await Haptics.impact({ style: ImpactStyle.Medium });
        setIsClearConfirmVisible(true);
        break;

      case 'print':
        if (currentOrder.length === 0) {
           alert("Ticket is empty. Nothing to print.");
           return;
        }
        await Haptics.impact({ style: ImpactStyle.Light });
        onPrintRequest();
        break;

      case 'edit':
        if (currentOrder.length === 0 && !editingTicket) {
           alert("No ticket to edit.");
           return;
        }
        await Haptics.impact({ style: ImpactStyle.Light });
        onSaveTicket();
        break;
      default:
        break;
    }
  };

  const handleConfirmClear = async () => {
    await Haptics.impact({ style: ImpactStyle.Heavy });
    onClearTicket();
    setIsClearConfirmVisible(false);
  };

  const handleCancelClear = async () => {
    await Haptics.impact({ style: ImpactStyle.Light });
    setIsClearConfirmVisible(false);
  };

  const handleCharge = async () => {
    await Haptics.impact({ style: ImpactStyle.Medium });
    onCharge();
  };

  const handleSaveOrder = async () => {
    await Haptics.impact({ style: ImpactStyle.Medium });
    handlePrimarySaveAction();
  };

  const renderActionButtons = () => {
    if (currentOrder.length > 0) {
      return (
        <button 
          onClick={handleSaveOrder}
          className="flex-1 bg-surface border-2 border-primary text-primary font-bold py-3.5 rounded-xl transition-all text-base shadow-sm hover:bg-primary/5 active:scale-[0.98] active:bg-primary/10"
        >
          {editingTicket ? 'Update Order' : 'Save Order'}
        </button>
      );
    }
    if (savedTickets.length > 0) {
      return (
        // Text is allowed to wrap to new lines. Flex layout ensures siblings stretch to same height.
        <button 
          onClick={async () => {
              await Haptics.impact({ style: ImpactStyle.Light });
              onOpenTickets();
          }}
          className="flex-1 bg-amber-500 text-white font-bold py-3 rounded-xl transition-all text-sm shadow-md hover:bg-amber-600 active:scale-[0.98] px-2 leading-tight break-words flex flex-col justify-center items-center"
        >
          <span>Open Tickets</span>
          <span className="text-xs">({savedTickets.length})</span>
        </button>
      );
    }
    return (
      <button 
        disabled
        className="flex-1 bg-surface-muted text-text-muted font-bold py-3.5 rounded-xl text-base cursor-not-allowed border border-transparent"
      >
        Save Order
      </button>
    );
  };

  const ticketHeaderTitle = useMemo(() => {
    if (editingTicket) return editingTicket.name;
    if (currentOrder.length > 0) return 'Current Order';
    return 'New Order';
  }, [editingTicket, currentOrder.length]);

  return (
    // Added pt-safe-top to outer container, remove fixed height from header, use inner container
    <section className={`${className} bg-surface border-l border-border h-full flex flex-col pt-safe-top relative`}>
      <header className="bg-surface shadow-sm w-full z-30 flex-shrink-0 border-b border-border">
        <div className="h-14 flex items-center justify-between px-4">
            <div className="flex items-center gap-3 overflow-hidden">
                {onClose && (
                    <button 
                    onClick={async () => {
                        await Haptics.impact({ style: ImpactStyle.Light });
                        onClose();
                    }} 
                    className="md:hidden p-2 -ml-2 text-text-secondary active:text-text-primary rounded-full hover:bg-surface-muted transition-colors"
                    >
                        <ArrowLeftIcon className="h-6 w-6" />
                    </button>
                )}
                <div className="flex flex-col min-w-0">
                    <h1 className="text-lg font-bold text-text-primary truncate leading-tight">{ticketHeaderTitle}</h1>
                    {currentOrder.length > 0 && (
                        <span className="text-xs text-text-secondary">{currentOrder.reduce((acc, i) => acc + i.quantity, 0)} items</span>
                    )}
                </div>
            </div>
            <div className="relative" ref={ticketMenuRef}>
                <button 
                onClick={(e) => { e.stopPropagation(); setTicketMenuOpen(prev => !prev); }} 
                className="p-2 text-text-secondary hover:text-text-primary rounded-full hover:bg-surface-muted transition-colors active:bg-surface-muted" 
                aria-label="Ticket options"
                >
                <ThreeDotsIcon className="h-6 w-6" />
