        if (!response || response.status !== 200 || response.type !== 'basic' && !event.request.url.includes('aistudiocdn.com')) {
          return response;
        }

        const url = event.request.url;
        const isExternalCdn = url.includes('aistudiocdn.com') || url.includes('esm.sh') || url.includes('google-apis') || url.includes('tailwindcss.com');
