// Pre-cache core local files
const STATIC_ASSETS = [
  './',
  'index.html',
  'index.tsx',
  'manifest.json'
];

self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => cache.addAll(STATIC_ASSETS))
  );
  self.skipWaiting();
});

self.addEventListener('activate', (event) => {
  event.waitUntil(self.clients.claim());
});

self.addEventListener('fetch', (event) => {
  // Only cache GET requests
  if (event.request.method !== 'GET') return;

  const url = new URL(event.request.url);

  // Strategy: Cache-First for CDNs (Tailwind, React, ESM)
  const isCDN = url.hostname.includes('tailwindcss.com') || 
                url.hostname.includes('aistudiocdn.com') || 
                url.hostname.includes('esm.sh');

  if (isCDN) {
    event.respondWith(
      caches.match(event.request).then((cached) => {
        return cached || fetch(event.request).then((response) => {
          const responseToCache = response.clone();
          caches.open(CACHE_NAME).then((cache) => {
            cache.put(event.request, responseToCache);
          });
          return response;
        });
      })
    );
    return;
  }

  // Network-First for local app files
  event.respondWith(
    fetch(event.request)
      .then((response) => {
        if (response.status === 200) {
          const responseToCache = response.clone();
          caches.open(CACHE_NAME).then((cache) => {
            cache.put(event.request, responseToCache);
          });
        }
        return response;
      })
      .catch(() => {
        return caches.match(event.request).then((cached) => {
          if (cached) return cached;
          if (event.request.mode === 'navigate') {
            return caches.match('index.html');
          }
        });
      })
  );
});

import React, { useEffect, useState, useRef, useMemo } from 'react';
import { useLocation, Navigate } from 'react-router-dom';
import Header from './Header';
import NavDrawer from './NavDrawer';
import { useAppContext } from '../context/AppContext';
import { NAV_LINKS } from '../constants';
import { Haptics, ImpactStyle } from '@capacitor/haptics';

import SalesScreen from '../screens/SalesScreen';
import ReceiptsScreen from '../screens/ReceiptsScreen';
import ItemsScreen from '../screens/ItemsScreen';
import SettingsScreen from '../screens/SettingsScreen';
import ReportsScreen from '../screens/ReportsScreen';
import AboutScreen from '../screens/AboutScreen';

const SCREEN_TIMEOUT = 10 * 60 * 1000; 

const KeepAliveScreen = React.memo(({ isVisible, children }: { isVisible: boolean, children: React.ReactNode }) => {
    return (
        <div 
            className={`flex flex-col h-full w-full absolute inset-0 bg-background transition-opacity duration-200 ${isVisible ? 'opacity-100 z-10' : 'opacity-0 z-[-1] pointer-events-none'}`}
            style={{ visibility: isVisible ? 'visible' : 'hidden' }}
        >
            {children}
        </div>
    );
});

const Layout: React.FC = () => {
  const { isDrawerOpen, openDrawer, closeDrawer } = useAppContext();
  const location = useLocation();
  const { pathname } = location;

  const [activeScreens, setActiveScreens] = useState<Record<string, number>>({ '/sales': Date.now() });

  // Gesture Refs
  const touchStartX = useRef<number>(0);
  const touchCurrentX = useRef<number>(0);
  const [swipeOffset, setSwipeOffset] = useState<number>(0);
  const [isSwiping, setIsSwiping] = useState<boolean>(false);
  const drawerWidth = Math.min(window.innerWidth * 0.85, 320);

  useEffect(() => {
      setActiveScreens(prev => ({ ...prev, [pathname]: Date.now() }));
  }, [pathname]);

  useEffect(() => {
      const interval = setInterval(() => {
          const now = Date.now();
          setActiveScreens(prev => {
              const next = { ...prev };
              let changed = false;
              Object.keys(next).forEach(path => {
                  if (path !== '/sales' && path !== pathname && now - next[path] > SCREEN_TIMEOUT) {
                      delete next[path];
                      changed = true;
                  }
              });
              return changed ? next : prev;
          });
      }, 60000);
      return () => clearInterval(interval);
  }, [pathname]);

  const displayTitle = useMemo(() => {
      const currentLink = NAV_LINKS.find(link => pathname.startsWith(link.path));
      return currentLink ? currentLink.label : 'Restaurant POS';
  }, [pathname]);

  const showDefaultHeader = !['/sales', '/receipts', '/settings', '/items', '/reports', '/about'].includes(pathname); 

  // --- NATIVE SWIPE GESTURE HANDLERS ---
  const handleTouchStart = (e: React.TouchEvent) => {
    if (isDrawerOpen) return; // Let NavDrawer handle its own close swipe if needed

    const x = e.touches[0].clientX;
    // Only detect swipe from the far left edge (standard mobile behavior)
    if (x < 40) {
        touchStartX.current = x;
        touchCurrentX.current = x;
        setIsSwiping(true);
    }
  };

  const handleTouchMove = (e: React.TouchEvent) => {
    if (!isSwiping) return;

    const x = e.touches[0].clientX;
    const deltaX = Math.max(0, x - touchStartX.current);

    // Threshold reached for haptic feedback
    if (deltaX > drawerWidth * 0.3 && swipeOffset <= drawerWidth * 0.3) {
        Haptics.impact({ style: ImpactStyle.Light }).catch(() => {});
    }

    setSwipeOffset(Math.min(deltaX, drawerWidth));
    touchCurrentX.current = x;
  };

  const handleTouchEnd = () => {
    if (!isSwiping) return;

    const velocity = touchCurrentX.current - touchStartX.current;

    // Snap open if pulled far enough or with high velocity
    if (swipeOffset > drawerWidth * 0.4 || velocity > 10) {
        openDrawer();
    }

    setIsSwiping(false);
    setSwipeOffset(0);
  };

  if (!['/sales', '/receipts', '/items', '/settings', '/reports', '/about'].some(p => pathname.startsWith(p))) {
      return <Navigate to="/sales" replace />;
  }

  return (
    <div 
        className="relative h-screen w-full overflow-hidden bg-background text-text-primary flex flex-col"
        onTouchStart={handleTouchStart}
        onTouchMove={handleTouchMove}
        onTouchEnd={handleTouchEnd}
    >
      {/* Backdrop for Swipe Gesture */}
      {isSwiping && (
          <div 
            className="fixed inset-0 bg-black/40 z-[55] pointer-events-none"
            style={{ opacity: (swipeOffset / drawerWidth) }}
          />
      )}

      {/* Swipe Gesture Visual Indicator (The drawer skeleton) */}
      {isSwiping && (
          <div 
            className="fixed top-0 left-0 bottom-0 bg-neutral-900 border-r border-neutral-800 z-[60] shadow-2xl pointer-events-none"
            style={{ 
                width: drawerWidth,
                transform: `translateX(${swipeOffset - drawerWidth}px)`,
                backfaceVisibility: 'hidden'
            }}
          />
      )}

      {showDefaultHeader && <Header title={displayTitle} onMenuClick={openDrawer} />}
      <NavDrawer />

      <main className="flex-1 relative overflow-hidden">
        <KeepAliveScreen isVisible={pathname === '/sales'}><SalesScreen /></KeepAliveScreen>
        {activeScreens['/receipts'] && <KeepAliveScreen isVisible={pathname === '/receipts'}><ReceiptsScreen /></KeepAliveScreen>}
        {activeScreens['/reports'] && <KeepAliveScreen isVisible={pathname === '/reports'}><ReportsScreen /></KeepAliveScreen>}
        {activeScreens['/items'] && <KeepAliveScreen isVisible={pathname === '/items'}><ItemsScreen /></KeepAliveScreen>}
        {activeScreens['/settings'] && <KeepAliveScreen isVisible={pathname === '/settings'}><SettingsScreen /></KeepAliveScreen>}
        {activeScreens['/about'] && <KeepAliveScreen isVisible={pathname === '/about'}><AboutScreen /></KeepAliveScreen>}
      </main>
    </div>
  );
};

export default Layout;

import React, { useState, useEffect, useRef } from 'react';
import { NavLink, useNavigate, useLocation } from 'react-router-dom';
import { useAppContext } from '../context/AppContext';
import { useStatusContext } from '../context/StatusContext';
import { NAV_LINKS, SignOutIcon, SyncIcon, OfflineIcon, CheckIcon, UserIcon, PowerIcon } from '../constants';
import ConfirmModal from './modals/ConfirmModal';
import { App } from '@capacitor/app';
import { Capacitor } from '@capacitor/core';
import { Haptics, ImpactStyle } from '@capacitor/haptics';

const NavDrawer: React.FC = () => {
  const { isDrawerOpen, closeDrawer, user, signOut, settings, currentOrder } = useAppContext();
  const { pendingSyncCount, isOnline } = useStatusContext();
  const [isSignOutModalOpen, setIsSignOutModalOpen] = useState(false);
  const [isExitModalOpen, setIsExitModalOpen] = useState(false);

  const navigate = useNavigate();
  const location = useLocation();

  // State Ref for Back Button Listener Closure
  const stateRef = useRef({ 
      isDrawerOpen, 
      isExitModalOpen, 
      pathname: location.pathname,
      hasCartItems: currentOrder.length > 0 
  });

  useEffect(() => {
      stateRef.current = { 
          isDrawerOpen, 
          isExitModalOpen, 
          pathname: location.pathname,
          hasCartItems: currentOrder.length > 0
      };
  }, [isDrawerOpen, isExitModalOpen, location.pathname, currentOrder.length]);

  // Hardware Back Button Handler
  useEffect(() => {
      if (!Capacitor.isNativePlatform()) return;

      const setupListener = async () => {
          await App.addListener('backButton', ({ canGoBack }) => {
              const { isDrawerOpen, isExitModalOpen, pathname } = stateRef.current;

              if (isDrawerOpen) {
                  closeDrawer();
                  return;
              } 

              if (isExitModalOpen) {
                  setIsExitModalOpen(false);
                  return;
              } 

              const openModals = document.querySelectorAll('.fixed.inset-0.z-50');
              if (openModals.length > 0) {
                  const closeBtn = openModals[openModals.length - 1].querySelector('button[aria-label="Close"], button:contains("Cancel"), button:contains("Close")');
                  if (closeBtn instanceof HTMLElement) {
                      closeBtn.click();
                  }
                  return;
              }

              if (pathname !== '/sales') {
                  navigate(-1);
              } else {
                  setIsExitModalOpen(true);
              }
          });
      };

      setupListener();
      return () => { App.removeAllListeners(); };
  }, [closeDrawer, navigate]);

  const handleSignOutClick = async () => {
    await Haptics.impact({ style: ImpactStyle.Light });
    closeDrawer();
    setIsSignOutModalOpen(true);
  };

  const confirmSignOut = () => {
    signOut();
    setIsSignOutModalOpen(false);
  };

  const handleExitClick = async () => {
    await Haptics.impact({ style: ImpactStyle.Medium });
    closeDrawer();
    setIsExitModalOpen(true);
  };

  const confirmExit = async () => {
    if (Capacitor.isNativePlatform()) {
        await App.exitApp();
    } else {
        window.close();
    }
    setIsExitModalOpen(false);
  };

  const handleNavClick = async () => {
      await Haptics.impact({ style: ImpactStyle.Light });
      closeDrawer();
  };

  return (
    <>
      <div
        onClick={closeDrawer}
        className={`fixed inset-0 bg-black/60 backdrop-blur-[2px] z-[60] transition-opacity duration-300 ease-out ${
          isDrawerOpen ? 'opacity-100 pointer-events-auto' : 'opacity-0 pointer-events-none'
        }`}
        aria-hidden="true"
      />

      <aside
        className={`fixed top-0 left-0 bottom-0 w-[85vw] max-w-[320px] bg-neutral-900 text-white z-[70] flex flex-col shadow-2xl transform transition-transform duration-300 cubic-bezier(0.4, 0, 0.2, 1) will-change-transform border-r border-neutral-800 ${
          isDrawerOpen ? 'translate-x-0' : '-translate-x-full'
        }`}
        style={{ backfaceVisibility: 'hidden' }}
      >
        <div className="p-6 border-b border-neutral-800 bg-neutral-900 pt-safe-top">
          <h2 className="text-xl font-bold text-white truncate tracking-tight">
            {settings.storeName || 'POS Menu'}
          </h2>
          <p className="text-xs text-neutral-500 mt-1 uppercase tracking-wider font-semibold">Point of Sale</p>
        </div>

        <nav className="flex-1 py-4 px-3 overflow-y-auto">
          <ul className="space-y-1">
            {NAV_LINKS.map(({ path, label, Icon }) => (
              <li key={path}>
                <NavLink
                  to={path}
                  onClick={handleNavClick}
                  className={({ isActive }) =>
                    `flex items-center px-4 py-3 text-sm font-medium rounded-full transition-all duration-200 group ${
                      isActive
                        ? 'bg-primary text-primary-content shadow-lg shadow-primary/20'
                        : 'text-neutral-400 hover:bg-neutral-800 hover:text-white'
                    }`
                  }
                >
                  <Icon className="h-5 w-5 mr-3" />
                  <span>{label}</span>
                </NavLink>
              </li>
            ))}
          </ul>
        </nav>

        <div className="px-4 py-2 mt-auto">
            <div className={`flex items-center gap-3 text-xs font-medium px-4 py-3 rounded-xl border ${
                !isOnline 
                  ? 'bg-neutral-800 border-neutral-700 text-neutral-400' 
                  : pendingSyncCount > 0 
                    ? 'bg-amber-900/20 border-amber-900/30 text-amber-400' 
                    : 'bg-emerald-900/20 border-emerald-900/30 text-emerald-400'
            }`}>
                {!isOnline ? (
                    <>
                        <OfflineIcon className="h-4 w-4 flex-shrink-0" />
                        <span>Offline Mode</span>
                    </>
                ) : pendingSyncCount > 0 ? (
                    <>
                        <SyncIcon className="h-4 w-4 animate-spin flex-shrink-0" />
                        <span>Syncing {pendingSyncCount} items...</span>
                    </>
                ) : (
                    <>
                        <CheckIcon className="h-4 w-4 flex-shrink-0" />
                        <span>System Synced</span>
                    </>
                )}
            </div>
        </div>

        <div className="p-4 border-t border-neutral-800 bg-neutral-900 pb-safe-bottom">
            <div className="flex items-center gap-3 mb-3 px-2">
                <div className="h-8 w-8 rounded-full bg-neutral-800 flex items-center justify-center text-neutral-400">
                     <UserIcon className="h-4 w-4" />
                </div>
                <div className="min-w-0">
                    <p className="text-sm font-medium text-white truncate">{user?.email}</p>
                    <p className="text-xs text-neutral-500">Administrator</p>
                </div>
            </div>

            <div className="grid grid-cols-2 gap-2">
                <button 
                    onClick={handleSignOutClick}
                    className="flex items-center justify-center px-3 py-2 text-sm font-medium transition-colors duration-200 text-neutral-400 hover:bg-neutral-800 hover:text-white rounded-lg border border-transparent"
                >
                    <SignOutIcon className="h-4 w-4 mr-2"/>
                    <span>Sign Out</span>
                </button>
                <button 
                    onClick={handleExitClick}
                    className="flex items-center justify-center px-3 py-2 text-sm font-medium transition-colors duration-200 text-red-400 hover:bg-red-500/10 hover:text-red-300 rounded-lg border border-transparent hover:border-red-500/20"
                >
                    <PowerIcon className="h-4 w-4 mr-2"/>
                    <span>Exit</span>
                </button>
            </div>
        </div>
      </aside>

      <ConfirmModal
        isOpen={isSignOutModalOpen}
        onClose={() => setIsSignOutModalOpen(false)}
        onConfirm={confirmSignOut}
        title="Sign Out"
        confirmText="Sign Out"
        confirmButtonClass="bg-red-600 hover:bg-red-700"
      >
        <p>Are you sure you want to sign out of your session?</p>
      </ConfirmModal>

      <ConfirmModal
        isOpen={isExitModalOpen}
        onClose={() => setIsExitModalOpen(false)}
        onConfirm={confirmExit}
        title="Exit Application"
        confirmText="Exit"
        confirmButtonClass="bg-red-600 hover:bg-red-700"
      >
        <p>Are you sure you want to close the application?</p>
      </ConfirmModal>
    </>
  );
};

