import React from 'react';
import { Item } from '../../types';
import { TrashIcon, PencilIcon } from '../../constants';
import { Haptics, ImpactStyle } from '@capacitor/haptics';

interface ItemTileProps {
    item: Item;
    mode: 'all' | 'grid';
    onAddItemToOrder: (item: Item) => void;
    onAssignItem: (slotIndex: number) => void;
    onRemoveFromGrid?: (slotIndex: number) => void;
    index: number;
    isFixedGrid: boolean;
    isEditing: boolean;
}

// Optimization: Prevent individual tiles from re-rendering unless their own ID, price, or edit status changes.
const ItemTile: React.FC<ItemTileProps> = React.memo(({ 
    item, mode, onAddItemToOrder, onAssignItem, onRemoveFromGrid, 
    index, isFixedGrid, isEditing 
}) => {

    const hasRealImage = item.imageUrl && item.imageUrl.startsWith('data:image');

    const aspectRatioClass = isFixedGrid 
        ? 'aspect-square md:aspect-auto md:h-full' 
        : 'aspect-square';

    if (isEditing && mode === 'grid') {
        return (
            <div className={`relative w-full rounded-xl overflow-hidden border-2 border-dashed border-primary/60 bg-primary/5 animate-pulse ${aspectRatioClass}`}>
                {hasRealImage && (
                    <img 
                        src={item.imageUrl} 
                        alt={item.name} 
                        className="absolute inset-0 w-full h-full object-cover z-0 opacity-30 grayscale pointer-events-none"
                    />
                )}
                <button
                    type="button"
                    onClick={async () => {
                        await Haptics.impact({ style: ImpactStyle.Light });
                        onAssignItem(index);
                    }}
                    className="absolute inset-0 flex flex-col items-center justify-center z-10 w-full h-full"
                >
                    <div className="bg-primary/10 p-2 rounded-full mb-1"><PencilIcon className="h-6 w-6 text-primary" /></div>
                    <span className="text-[10px] uppercase font-bold text-primary bg-surface/90 px-2 py-0.5 rounded-full shadow-sm">Change</span>
                </button>
                <button 
                    type="button"
                    onClick={async (e) => {
                        e.stopPropagation();
                        await Haptics.notification({ type: ImpactStyle.Heavy });
                        if(onRemoveFromGrid) onRemoveFromGrid(index);
                    }}
                    className="absolute top-1 right-1 z-20 bg-red-500 text-white rounded-full p-1.5 shadow-md active:scale-90"
                >
                    <TrashIcon className="h-4 w-4" />
                </button>
                <div className="absolute bottom-0 left-0 right-0 p-1.5 bg-black/50 backdrop-blur-sm z-0 pointer-events-none">
                    <h3 className="font-semibold text-white text-xs text-center truncate">{item.name}</h3>
                </div>
            </div>
        );
    }

    const handleClick = async () => {
        await Haptics.impact({ style: ImpactStyle.Light });
        onAddItemToOrder(item);
    };

    const PriceBadge = () => (
        <div className="absolute top-1 right-1 md:top-2 md:right-2 bg-black/60 text-white backdrop-blur-sm px-1.5 py-0.5 md:px-2 md:py-1 rounded-md text-[10px] md:text-xs font-bold shadow-lg z-10 tabular-nums border border-white/20 pointer-events-none">
            ₹{item.price.toFixed(0)}
        </div>
    );

    return (
        <button
            type="button"
            onClick={handleClick}
            className={`relative w-full rounded-xl overflow-hidden cursor-pointer shadow-sm border border-border/50 bg-surface-muted group select-none ${aspectRatioClass}`}
        >
            {hasRealImage ? (
                <div className="w-full h-full relative pointer-events-none">
                    <img src={item.imageUrl} alt={item.name} className="absolute inset-0 w-full h-full object-cover z-0" loading="lazy" />
                    <div className="absolute inset-0 bg-black opacity-0 group-active:opacity-20 z-30 transition-none" />
                    <PriceBadge />
                    <div className="absolute inset-x-0 bottom-0 h-1/2 bg-gradient-to-t from-black/80 via-black/40 to-transparent z-10" />
                    <div className="absolute bottom-0 left-0 right-0 p-2 z-20">
                        <h3 className="font-bold text-white text-xs md:text-sm leading-tight text-center line-clamp-2">{item.name}</h3>
                    </div>
                </div>
            ) : (
                <div className="w-full h-full flex flex-col justify-center items-center p-2 text-center pointer-events-none relative z-0">
                    <PriceBadge />
                    <div className="w-6 h-1 md:w-8 bg-primary/20 rounded-full mb-2" />
                    <h3 className="font-bold text-text-primary text-xs md:text-base leading-snug line-clamp-3">{item.name}</h3>
                </div>
            )}
        </button>
    );
}, (prev, next) => {
    return prev.item.id === next.item.id && 
           prev.item.price === next.item.price && 
           prev.isEditing === next.isEditing &&
           prev.item.stock === next.item.stock;
});

export default ItemTile;

import React, { createContext, useState, useContext, ReactNode, useCallback, useEffect, useMemo } from 'react';
import { 
    Printer, Receipt, Item, AppSettings, BackupData, SavedTicket, 
    CustomGrid, PaymentType, OrderItem, AppContextType, Table, Theme
} from '../types';
import { Capacitor } from '@capacitor/core';
import { Filesystem, Directory, Encoding } from '@capacitor/filesystem';
import { Share } from '@capacitor/share';
import { exportItemsToCsv } from '../utils/csvHelper';
import { requestAppPermissions } from '../utils/permissions';
import { requestNotificationPermission, scheduleDailySummary, cancelDailySummary, sendLowStockAlert } from '../utils/notificationHelper';
import { db, signOutUser, auth } from '../firebase';
import { collection, onSnapshot, doc, setDoc, deleteDoc, writeBatch, Timestamp, query, orderBy, limit, getDocs, getDoc, increment } from 'firebase/firestore';
import { onAuthStateChanged, User } from 'firebase/auth';
import { idb } from '../utils/indexedDB'; 
import { useStatusContext } from './StatusContext';

const DEFAULT_SETTINGS: AppSettings = { 
    taxEnabled: true, 
    taxRate: 5, 
    storeName: 'My Restaurant',
    storeAddress: '123 Food Street, Flavor Town',
    receiptFooter: 'Follow us @myrestaurant',
    reportsPIN: '',
    shiftMorningStart: '06:00',
    shiftMorningEnd: '17:30',
    shiftNightEnd: '05:00',
    notificationsEnabled: false,
    notifyLowStock: false,
    lowStockThreshold: 10,
    notifyDailySummary: false,
    dailySummaryTime: '22:00'
};

const AppContext = createContext<AppContextType | undefined>(undefined);

const SETTINGS_CACHE_KEY = 'pos_settings_cache';
const ONBOARDING_COMPLETED_KEY = 'pos_onboarding_completed_v1';
const ACTIVE_GRID_KEY = 'pos_active_grid_id';

export const AppProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const { setPendingSyncCount } = useStatusContext();
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [showOnboarding, setShowOnboarding] = useState(() => !localStorage.getItem(ONBOARDING_COMPLETED_KEY));
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);
  const [headerTitle, setHeaderTitle] = useState('');
  const [isReportsUnlocked, setReportsUnlocked] = useState(false);
  const [theme, setThemeState] = useState<Theme>(() => (localStorage.getItem('theme') as Theme) || 'system');

  const setTheme = useCallback((newTheme: Theme) => {
    setThemeState(newTheme);
    localStorage.setItem('theme', newTheme);
  }, []);

  useEffect(() => {
    const mediaQuery = window.matchMedia('(prefers-color-scheme: dark)');
    const applyTheme = () => {
        let effectiveTheme = theme === 'system' ? (mediaQuery.matches ? 'dark' : 'light') : theme;
        document.documentElement.classList.toggle('dark', effectiveTheme === 'dark');
    };
    applyTheme();
    mediaQuery.addEventListener('change', applyTheme);
    return () => mediaQuery.removeEventListener('change', applyTheme);
  }, [theme]);

  const openDrawer = useCallback(() => setIsDrawerOpen(true), []);
  const closeDrawer = useCallback(() => setIsDrawerOpen(false), []);
  const toggleDrawer = useCallback(() => setIsDrawerOpen(prev => !prev), []);

  const [settings, setSettingsState] = useState<AppSettings>(DEFAULT_SETTINGS);
  const [items, setItemsState] = useState<Item[]>([]);
  const [customGrids, setCustomGridsState] = useState<CustomGrid[]>([]);
  const [receipts, setReceiptsState] = useState<Receipt[]>([]);
  const [printers, setPrintersState] = useState<Printer[]>([]);
  const [paymentTypes, setPaymentTypesState] = useState<PaymentType[]>([]);
  const [savedTickets, setSavedTicketsState] = useState<SavedTicket[]>([]);
  const [tables, setTablesState] = useState<Table[]>([]);
  const [activeGridId, setActiveGridIdState] = useState<string>(() => localStorage.getItem(ACTIVE_GRID_KEY) || 'All');

  const setActiveGridId = useCallback((id: string) => {
      setActiveGridIdState(id);
      localStorage.setItem(ACTIVE_GRID_KEY, id);
  }, []);

  const [currentOrder, setCurrentOrder] = useState<OrderItem[]>([]);

  // CART ACTIONS - Memoized to prevent children re-renders
  const addToOrder = useCallback((item: Item) => {
    setCurrentOrder(current => {
      const lastItem = current.length > 0 ? current[current.length - 1] : null;
      if (lastItem && lastItem.id === item.id && lastItem.price === item.price) {
        const newOrder = [...current];
        newOrder[newOrder.length - 1] = { ...lastItem, quantity: lastItem.quantity + 1 };
        return newOrder;
      }
      return [...current, { ...item, quantity: 1, lineItemId: `L${Date.now()}-${Math.random()}` }];
    });
  }, []);

  const removeFromOrder = useCallback((lineItemId: string) => {
    setCurrentOrder(current => {
      const itemIndex = current.findIndex(i => i.lineItemId === lineItemId);
      if (itemIndex === -1) return current;
      const itemToUpdate = current[itemIndex];
      if (itemToUpdate.quantity > 1) {
        const newOrder = [...current];
        newOrder[itemIndex] = { ...itemToUpdate, quantity: itemToUpdate.quantity - 1 };
        return newOrder;
      }
      return current.filter(i => i.lineItemId !== lineItemId);
    });
  }, []);

  const deleteLineItem = useCallback((lineItemId: string) => {
    setCurrentOrder(prev => prev.filter(i => i.lineItemId !== lineItemId));
  }, []);

  const updateOrderItemQuantity = useCallback((lineItemId: string, newQuantity: number) => {
    if (isNaN(newQuantity) || newQuantity <= 0) deleteLineItem(lineItemId);
    else setCurrentOrder(prev => prev.map(i => i.lineItemId === lineItemId ? { ...i, quantity: newQuantity } : i));
  }, [deleteLineItem]);

  const clearOrder = useCallback(() => setCurrentOrder([]), []);
  const loadOrder = useCallback((items: OrderItem[]) => setCurrentOrder(items.map(item => ({ ...item, lineItemId: item.lineItemId || `L${Date.now()}-${Math.random()}` }))), []);

  useEffect(() => {
    const unsubAuth = onAuthStateChanged(auth, async (currentUser) => {
        if (currentUser) {
            setUser(currentUser);
            const uid = currentUser.uid;
            try {
                const settingsSnap = await getDoc(doc(db, 'users', uid, 'config', 'settings'));
                if (settingsSnap.exists()) setSettingsState({ ...DEFAULT_SETTINGS, ...settingsSnap.data() as AppSettings });

                const [itemsSnap, printersSnap, ptSnap, tblSnap, tktSnap, grdSnap] = await Promise.all([
                    getDocs(collection(db, 'users', uid, 'items')),
                    getDocs(collection(db, 'users', uid, 'printers')),
                    getDocs(collection(db, 'users', uid, 'payment_types')),
                    getDocs(query(collection(db, 'users', uid, 'tables'), orderBy('order'))),
                    getDocs(collection(db, 'users', uid, 'saved_tickets')),
                    getDocs(query(collection(db, 'users', uid, 'custom_grids'), orderBy('order')))
                ]);

                setItemsState(itemsSnap.docs.map(d => d.data() as Item));
                setPrintersState(printersSnap.docs.map(d => d.data() as Printer));
                setPaymentTypesState(ptSnap.docs.map(d => d.data() as PaymentType));
                setTablesState(tblSnap.docs.map(d => d.data() as Table));
                setSavedTicketsState(tktSnap.docs.map(d => d.data() as SavedTicket));
                setCustomGridsState(grdSnap.docs.map(d => d.data() as CustomGrid));
            } catch (e) { console.error(e); }

            const unsubReceipts = onSnapshot(query(collection(db, 'users', uid, 'receipts'), orderBy('date', 'desc'), limit(50)), (snap) => {
                setReceiptsState(snap.docs.map(d => ({ ...d.data(), date: (d.data().date as Timestamp).toDate() } as Receipt)));
                setPendingSyncCount(snap.docs.filter(d => d.metadata.hasPendingWrites).length);
            });
            setIsLoading(false);
            return () => unsubReceipts();
        } else {
            setUser(null);
            setIsLoading(false);
        }
    });
    return () => unsubAuth();
  }, [setPendingSyncCount]);

  const addReceipt = useCallback(async (receipt: Receipt) => {
    // 1. STRIP BASE64 IMAGES FOR PERSISTENCE (Optimization: Prevent massive storage lag)
    const persistenceFriendlyReceipt = {
        ...receipt,
        items: receipt.items.map(item => ({ ...item, imageUrl: '' }))
    };

    setReceiptsState(prev => [receipt, ...prev]);
    idb.saveReceipt(persistenceFriendlyReceipt); 
    const batch = writeBatch(db);
    batch.set(doc(db, 'users', user!.uid, 'receipts', receipt.id), persistenceFriendlyReceipt);

    const updatedItems = [...items];
    receipt.items.forEach(orderItem => {
        const idx = updatedItems.findIndex(i => i.id === orderItem.id);
        if (idx > -1) {
            updatedItems[idx].stock = Math.max(0, updatedItems[idx].stock - orderItem.quantity);
            batch.update(doc(db, 'users', user!.uid, 'items', orderItem.id), { stock: increment(-orderItem.quantity) });
            if (settings.notifyLowStock && updatedItems[idx].stock <= (settings.lowStockThreshold || 0)) {
                sendLowStockAlert(updatedItems[idx].name, updatedItems[idx].stock);
            }
        }
    });
    setItemsState(updatedItems);
    try { await batch.commit(); } catch (e) { console.error("Sync failed", e); }
  }, [user, items, settings]);

  const value = useMemo(() => ({
      user, signOut: signOutUser,
      isDrawerOpen, openDrawer, closeDrawer, toggleDrawer, 
      headerTitle, setHeaderTitle, theme, setTheme,
      showOnboarding, completeOnboarding: async () => {
          if (Capacitor.isNativePlatform()) {
              const p = await requestAppPermissions();
              await requestNotificationPermission();
              if (!p) return false;
          }
          localStorage.setItem(ONBOARDING_COMPLETED_KEY, 'true');
          setShowOnboarding(false);
          return true;
      },
      isLoading, settings, updateSettings: async (s: Partial<AppSettings>) => {
          const next = { ...settings, ...s };
          setSettingsState(next);
          localStorage.setItem(SETTINGS_CACHE_KEY, JSON.stringify(next));
          await setDoc(doc(db, 'users', user!.uid, 'config', 'settings'), next, { merge: true });
      },
      printers, addPrinter: async (p: Printer) => {
          setPrintersState(v => [...v, p]);
          await setDoc(doc(db, 'users', user!.uid, 'printers', p.id), p);
      },
      removePrinter: async (id: string) => {
          setPrintersState(v => v.filter(p => p.id !== id));
          await deleteDoc(doc(db, 'users', user!.uid, 'printers', id));
      },
      paymentTypes, addPaymentType: async (p: any) => {
          const id = `pt_${Date.now()}`;
          const pt = { ...p, id, enabled: true, type: 'other' };
          setPaymentTypesState(v => [...v, pt]);
          await setDoc(doc(db, 'users', user!.uid, 'payment_types', id), pt);
      },
      updatePaymentType: async (p: PaymentType) => {
          setPaymentTypesState(v => v.map(i => i.id === p.id ? p : i));
          await setDoc(doc(db, 'users', user!.uid, 'payment_types', p.id), p);
      },
      removePaymentType: async (id: string) => {
          setPaymentTypesState(v => v.filter(p => p.id !== id));
          await deleteDoc(doc(db, 'users', user!.uid, 'payment_types', id));
      },
      receipts, addReceipt, loadMoreReceipts: async () => {}, hasMoreReceipts: false, 
      deleteReceipt: async (id: string) => {
          setReceiptsState(v => v.filter(r => r.id !== id));
          await deleteDoc(doc(db, 'users', user!.uid, 'receipts', id));
      },
      items, addItem: async (i: Item) => {
          setItemsState(v => [...v, i]);
          await setDoc(doc(db, 'users', user!.uid, 'items', i.id), i);
      },
      updateItem: async (i: Item) => {
          setItemsState(v => v.map(x => x.id === i.id ? i : x));
          await setDoc(doc(db, 'users', user!.uid, 'items', i.id), i);
      },
      deleteItem: async (id: string) => {
          setItemsState(v => v.filter(x => x.id !== id));
          await deleteDoc(doc(db, 'users', user!.uid, 'items', id));
      },
      savedTickets, saveTicket: async (t: SavedTicket) => {
          setSavedTicketsState(v => [...v.filter(x => x.id !== t.id), t]);
          await setDoc(doc(db, 'users', user!.uid, 'saved_tickets', t.id), t);
      },
      removeTicket: async (id: string) => {
          setSavedTicketsState(v => v.filter(x => x.id !== id));
          await deleteDoc(doc(db, 'users', user!.uid, 'saved_tickets', id));
      },
      mergeTickets: async () => {},
      customGrids, addCustomGrid: async (g: CustomGrid) => {
          setCustomGridsState(v => [...v, g]);
          await setDoc(doc(db, 'users', user!.uid, 'custom_grids', g.id), g);
      },
      updateCustomGrid: async (g: CustomGrid) => {
          setCustomGridsState(v => v.map(x => x.id === g.id ? g : x));
          await setDoc(doc(db, 'users', user!.uid, 'custom_grids', g.id), g);
      },
      deleteCustomGrid: async (id: string) => {
          setCustomGridsState(v => v.filter(x => x.id !== id));
          await deleteDoc(doc(db, 'users', user!.uid, 'custom_grids', id));
      },
      setCustomGrids: async (gs: CustomGrid[]) => {
          setCustomGridsState(gs);
          const batch = writeBatch(db);
          gs.forEach(g => batch.set(doc(db, 'users', user!.uid, 'custom_grids', g.id), g));
          await batch.commit();
      },
      tables, addTable: async (n: string) => {
          const t = { id: `tbl_${Date.now()}`, name: n, order: tables.length };
          setTablesState(v => [...v, t]);
          await setDoc(doc(db, 'users', user!.uid, 'tables', t.id), t);
      },
      updateTable: async (t: Table) => {
          setTablesState(v => v.map(x => x.id === t.id ? t : x));
          await setDoc(doc(db, 'users', user!.uid, 'tables', t.id), t);
      },
      removeTable: async (id: string) => {
          setTablesState(v => v.filter(x => x.id !== id));
          await deleteDoc(doc(db, 'users', user!.uid, 'tables', id));
      },
      setTables: async (ts: Table[]) => {
          setTablesState(ts);
          const batch = writeBatch(db);
          ts.forEach(t => batch.set(doc(db, 'users', user!.uid, 'tables', t.id), t));
          await batch.commit();
      },
      activeGridId, setActiveGridId,
      currentOrder, addToOrder, removeFromOrder, deleteLineItem, updateOrderItemQuantity, clearOrder, loadOrder,
      exportData: () => {}, restoreData: () => {}, 
      exportItemsCsv: async () => {
          const csvString = exportItemsToCsv(items);
          const fileName = `inventory_export_${new Date().toISOString().slice(0, 10)}.csv`;
          try {
              if (Capacitor.isNativePlatform()) {
                  const result = await Filesystem.writeFile({ path: fileName, data: csvString, directory: Directory.Documents, encoding: Encoding.UTF8 });
                  await Share.share({ url: result.uri, title: 'Export Inventory' });
              } else {
                  const blob = new Blob([csvString], { type: 'text/csv;charset=utf-8;' });
                  const link = document.createElement("a");
                  link.setAttribute("href", URL.createObjectURL(blob));
                  link.setAttribute("download", fileName);
                  document.body.appendChild(link);
                  link.click();
                  document.body.removeChild(link);
              }
          } catch (error) { console.error("Export failed", error); }
      }, 
      replaceItems: (is: Item[]) => {
          setItemsState(is);
          const batch = writeBatch(db);
          is.forEach(i => batch.set(doc(db, 'users', user!.uid, 'items', i.id), i));
          batch.commit();
      },
      isReportsUnlocked, setReportsUnlocked
  }), [user, isDrawerOpen, headerTitle, theme, showOnboarding, isLoading, settings, items, customGrids, receipts, printers, paymentTypes, savedTickets, tables, activeGridId, currentOrder, isReportsUnlocked, addReceipt, addToOrder, removeFromOrder, deleteLineItem, updateOrderItemQuantity, clearOrder, loadOrder]);

  return <AppContext.Provider value={value}>{children}</AppContext.Provider>;
};

export const useAppContext = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error('useAppContext must be used within an AppProvider');
  return context;
};

import React, { useEffect, useState, useMemo } from 'react';
import { useLocation, Navigate } from 'react-router-dom';
import Header from './Header';
import NavDrawer from './NavDrawer';
import { useAppContext } from '../context/AppContext';
import { NAV_LINKS } from '../constants';

import SalesScreen from '../screens/SalesScreen';
import ReceiptsScreen from '../screens/ReceiptsScreen';
import ItemsScreen from '../screens/ItemsScreen';
import SettingsScreen from '../screens/SettingsScreen';
import ReportsScreen from '../screens/ReportsScreen';
import AboutScreen from '../screens/AboutScreen';

const SCREEN_TIMEOUT = 10 * 60 * 1000; // 10 Minutes

const KeepAliveScreen = React.memo(({ isVisible, children }: { isVisible: boolean, children: React.ReactNode }) => {
    return (
        <div 
            className={`flex flex-col h-full w-full absolute inset-0 bg-background transition-opacity duration-200 ${isVisible ? 'opacity-100 z-10' : 'opacity-0 z-[-1] pointer-events-none'}`}
            style={{ visibility: isVisible ? 'visible' : 'hidden' }}
        >
            {children}
        </div>
    );
});

const Layout: React.FC = () => {
  const { isDrawerOpen, openDrawer } = useAppContext();
  const location = useLocation();
  const { pathname } = location;

  // Track last used timestamp for each screen to free up memory
  const [activeScreens, setActiveScreens] = useState<Record<string, number>>({ '/sales': Date.now() });

  useEffect(() => {
      setActiveScreens(prev => ({ ...prev, [pathname]: Date.now() }));
  }, [pathname]);

  // Aggressive memory cleanup for Android WebViews
  useEffect(() => {
      const interval = setInterval(() => {
          const now = Date.now();
          setActiveScreens(prev => {
              const next = { ...prev };
              let changed = false;
              Object.keys(next).forEach(path => {
                  // Never unmount Sales; unmount others if inactive
                  if (path !== '/sales' && path !== pathname && now - next[path] > SCREEN_TIMEOUT) {
                      delete next[path];
                      changed = true;
                  }
              });
              return changed ? next : prev;
          });
      }, 60000);
      return () => clearInterval(interval);
  }, [pathname]);

  const displayTitle = useMemo(() => {
      const currentLink = NAV_LINKS.find(link => pathname.startsWith(link.path));
      return currentLink ? currentLink.label : 'Restaurant POS';
  }, [pathname]);

  const showDefaultHeader = !['/sales', '/receipts', '/settings', '/items', '/reports', '/about'].includes(pathname); 

  if (!['/sales', '/receipts', '/items', '/settings', '/reports', '/about'].some(p => pathname.startsWith(p))) {
      return <Navigate to="/sales" replace />;
  }

  return (
    <div className="relative h-screen w-full overflow-hidden bg-background text-text-primary flex flex-col">
      {showDefaultHeader && <Header title={displayTitle} onMenuClick={openDrawer} />}
      <NavDrawer />

      <main className="flex-1 relative overflow-hidden">
        <KeepAliveScreen isVisible={pathname === '/sales'}><SalesScreen /></KeepAliveScreen>
        {activeScreens['/receipts'] && <KeepAliveScreen isVisible={pathname === '/receipts'}><ReceiptsScreen /></KeepAliveScreen>}
        {activeScreens['/reports'] && <KeepAliveScreen isVisible={pathname === '/reports'}><ReportsScreen /></KeepAliveScreen>}
        {activeScreens['/items'] && <KeepAliveScreen isVisible={pathname === '/items'}><ItemsScreen /></KeepAliveScreen>}
        {activeScreens['/settings'] && <KeepAliveScreen isVisible={pathname === '/settings'}><SettingsScreen /></KeepAliveScreen>}
        {activeScreens['/about'] && <KeepAliveScreen isVisible={pathname === '/about'}><AboutScreen /></KeepAliveScreen>}
      </main>
    </div>
  );
};

export default Layout;

import React, { useEffect, useState } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import { AppProvider, useAppContext } from './context/AppContext';
import { StatusProvider } from './context/StatusContext';
import Layout from './components/Layout';
import LoginScreen from './screens/LoginScreen';
import SignupScreen from './screens/SignupScreen';
import OnboardingScreen from './screens/OnboardingScreen';
import { StoreIcon } from './constants';
import { Capacitor } from '@capacitor/core';
import { StatusBar, Style } from '@capacitor/status-bar';

/**
 * FAIL-SAFE ERROR BOUNDARY
 * If a component crashes due to corrupt data, this prevents the whole app from going white.
 */
class ErrorBoundary extends React.Component<{children: React.ReactNode}, {hasError: boolean}> {
  constructor(props: any) {
    super(props);
    this.state = { hasError: false };
  }
  static getDerivedStateFromError() { return { hasError: true }; }
  render() {
    if (this.state.hasError) {
      return (
        <div className="flex h-screen w-full items-center justify-center bg-background p-6 text-center">
          <div className="max-w-md">
            <h2 className="text-2xl font-bold text-text-primary mb-4">Something went wrong</h2>
            <p className="text-text-secondary mb-8">The app encountered an unexpected error. Don't worry, your data is safe.</p>
            <button 
                onClick={() => window.location.reload()} 
                className="w-full bg-primary text-primary-content font-bold py-4 rounded-xl shadow-lg"
            >
                Restart Application
            </button>
          </div>
        </div>
      );
    }
    return this.props.children;
  }
}

const AppRoutes: React.FC = () => {
    const { user, isLoading, showOnboarding, theme } = useAppContext();

    // --- Native Status Bar Sync ---
    useEffect(() => {
        if (Capacitor.isNativePlatform()) {
            const configStatusBar = async () => {
                try {
                    if (Capacitor.getPlatform() === 'android') {
                        await StatusBar.setOverlaysWebView({ overlay: false });
                    }
                    const style = theme === 'dark' ? Style.Dark : Style.Light;
                    await StatusBar.setStyle({ style });
                    if (Capacitor.getPlatform() === 'android') {
                        const color = theme === 'dark' ? '#262626' : '#FFFFFF';
                        await StatusBar.setBackgroundColor({ color });
                    }
                } catch (e) {
                    // Fail silently for non-critical native features
                }
            };
            configStatusBar();
        }
    }, [theme]);

    if (showOnboarding) {
        return <OnboardingScreen />;
    }

    if (isLoading) {
        return (
            <div className="flex h-screen w-full items-center justify-center bg-surface-muted">
               <div className="flex flex-col items-center">
                   <div className="relative mb-6">
                        <div className="absolute inset-0 bg-primary/20 rounded-full animate-ping"></div>
                        <div className="relative bg-surface p-4 rounded-full shadow-lg">
                             <StoreIcon className="h-10 w-10 text-primary" />
                        </div>
                   </div>
                   <h2 className="text-lg font-bold text-text-primary">Restaurant POS</h2>
                   <p className="text-sm text-text-secondary mt-1">Loading your workspace...</p>
               </div>
            </div>
        );
    }

    if (!user) {
        return (
            <Routes>
                <Route path="/login" element={<LoginScreen />} />
                <Route path="/signup" element={<SignupScreen />} />
                <Route path="*" element={<Navigate to="/login" replace />} />
            </Routes>
        );
    }

    return (
        <Routes>
           <Route path="/*" element={<Layout />} />
        </Routes>
    );
};


const App: React.FC = () => {
  return (
    <ErrorBoundary>
        <HashRouter>
          <StatusProvider>
            <AppProvider>
              <AppRoutes />
            </AppProvider>
          </StatusProvider>
        </HashRouter>
    </ErrorBoundary>
  );
};

export default App;

import React, { createContext, useState, useContext, ReactNode, useCallback, useEffect, useMemo } from 'react';
import { 
    Printer, Receipt, Item, AppSettings, BackupData, SavedTicket, 
    CustomGrid, PaymentType, OrderItem, AppContextType, Table, Theme
} from '../types';
import { Capacitor } from '@capacitor/core';
import { Filesystem, Directory, Encoding } from '@capacitor/filesystem';
import { Share } from '@capacitor/share';
import { exportItemsToCsv } from '../utils/csvHelper';
import { requestAppPermissions } from '../utils/permissions';
import { requestNotificationPermission, scheduleDailySummary, cancelDailySummary, sendLowStockAlert } from '../utils/notificationHelper';
import { db, signOutUser, auth } from '../firebase';
import { collection, onSnapshot, doc, setDoc, deleteDoc, writeBatch, Timestamp, query, orderBy, limit, getDocs, getDoc, increment } from 'firebase/firestore';
import { onAuthStateChanged, User } from 'firebase/auth';
import { idb } from '../utils/indexedDB'; 
import { useStatusContext } from './StatusContext';

const DEFAULT_SETTINGS: AppSettings = { 
    taxEnabled: true, 
    taxRate: 5, 
    storeName: 'My Restaurant',
    storeAddress: '123 Food Street, Flavor Town',
    receiptFooter: 'Follow us @myrestaurant',
    reportsPIN: '',
    shiftMorningStart: '06:00',
    shiftMorningEnd: '17:30',
    shiftNightEnd: '05:00',
    notificationsEnabled: false,
    notifyLowStock: false,
    lowStockThreshold: 10,
    notifyDailySummary: false,
    dailySummaryTime: '22:00'
};

const AppContext = createContext<AppContextType | undefined>(undefined);

const SETTINGS_CACHE_KEY = 'pos_settings_cache';
const ONBOARDING_COMPLETED_KEY = 'pos_onboarding_completed_v1';
const ACTIVE_GRID_KEY = 'pos_active_grid_id';

export const AppProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const { setPendingSyncCount } = useStatusContext();
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [showOnboarding, setShowOnboarding] = useState(() => !localStorage.getItem(ONBOARDING_COMPLETED_KEY));
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);
  const [headerTitle, setHeaderTitle] = useState('');
  const [isReportsUnlocked, setReportsUnlocked] = useState(false);
  const [theme, setThemeState] = useState<Theme>(() => (localStorage.getItem('theme') as Theme) || 'system');

  const setTheme = useCallback((newTheme: Theme) => {
    setThemeState(newTheme);
    localStorage.setItem('theme', newTheme);
  }, []);

  useEffect(() => {
    const mediaQuery = window.matchMedia('(prefers-color-scheme: dark)');
    const applyTheme = () => {
        let effectiveTheme = theme === 'system' ? (mediaQuery.matches ? 'dark' : 'light') : theme;
        document.documentElement.classList.toggle('dark', effectiveTheme === 'dark');
    };
    applyTheme();
    mediaQuery.addEventListener('change', applyTheme);
    return () => mediaQuery.removeEventListener('change', applyTheme);
  }, [theme]);

  const openDrawer = useCallback(() => setIsDrawerOpen(true), []);
  const closeDrawer = useCallback(() => setIsDrawerOpen(false), []);
  const toggleDrawer = useCallback(() => setIsDrawerOpen(prev => !prev), []);

  const [settings, setSettingsState] = useState<AppSettings>(DEFAULT_SETTINGS);
  const [items, setItemsState] = useState<Item[]>([]);
  const [customGrids, setCustomGridsState] = useState<CustomGrid[]>([]);
  const [receipts, setReceiptsState] = useState<Receipt[]>([]);
  const [printers, setPrintersState] = useState<Printer[]>([]);
  const [paymentTypes, setPaymentTypesState] = useState<PaymentType[]>([]);
  const [savedTickets, setSavedTicketsState] = useState<SavedTicket[]>([]);
  const [tables, setTablesState] = useState<Table[]>([]);
  const [activeGridId, setActiveGridIdState] = useState<string>(() => localStorage.getItem(ACTIVE_GRID_KEY) || 'All');

  const setActiveGridId = useCallback((id: string) => {
      setActiveGridIdState(id);
      localStorage.setItem(ACTIVE_GRID_KEY, id);
  }, []);

  const [currentOrder, setCurrentOrder] = useState<OrderItem[]>([]);

  // CART ACTIONS - Robust memoization to prevent heavy grid re-renders
  const addToOrder = useCallback((item: Item) => {
    setCurrentOrder(current => {
      const lastItem = current.length > 0 ? current[current.length - 1] : null;
      if (lastItem && lastItem.id === item.id && lastItem.price === item.price) {
        const newOrder = [...current];
        newOrder[newOrder.length - 1] = { ...lastItem, quantity: lastItem.quantity + 1 };
        return newOrder;
      }
      // Strip base64 image immediately when adding to cart to keep memory footprint low
      const orderItem: OrderItem = { 
          ...item, 
          imageUrl: '', 
          quantity: 1, 
          lineItemId: `L${Date.now()}-${Math.random()}` 
      };
      return [...current, orderItem];
    });
  }, []);

  const removeFromOrder = useCallback((lineItemId: string) => {
    setCurrentOrder(current => {
      const itemIndex = current.findIndex(i => i.lineItemId === lineItemId);
      if (itemIndex === -1) return current;
      const itemToUpdate = current[itemIndex];
      if (itemToUpdate.quantity > 1) {
        const newOrder = [...current];
        newOrder[itemIndex] = { ...itemToUpdate, quantity: itemToUpdate.quantity - 1 };
        return newOrder;
      }
      return current.filter(i => i.lineItemId !== lineItemId);
    });
  }, []);

  const deleteLineItem = useCallback((lineItemId: string) => {
    setCurrentOrder(prev => prev.filter(i => i.lineItemId !== lineItemId));
  }, []);

  const updateOrderItemQuantity = useCallback((lineItemId: string, newQuantity: number) => {
    if (isNaN(newQuantity) || newQuantity <= 0) deleteLineItem(lineItemId);
    else setCurrentOrder(prev => prev.map(i => i.lineItemId === lineItemId ? { ...i, quantity: newQuantity } : i));
  }, [deleteLineItem]);

  const clearOrder = useCallback(() => setCurrentOrder([]), []);
  const loadOrder = useCallback((items: OrderItem[]) => setCurrentOrder(items.map(item => ({ ...item, lineItemId: item.lineItemId || `L${Date.now()}-${Math.random()}` }))), []);

  useEffect(() => {
    const unsubAuth = onAuthStateChanged(auth, async (currentUser) => {
        if (currentUser) {
            setUser(currentUser);
            const uid = currentUser.uid;
            try {
                const settingsSnap = await getDoc(doc(db, 'users', uid, 'config', 'settings'));
                if (settingsSnap.exists()) setSettingsState({ ...DEFAULT_SETTINGS, ...settingsSnap.data() as AppSettings });

                const [itemsSnap, printersSnap, ptSnap, tblSnap, tktSnap, grdSnap] = await Promise.all([
                    getDocs(collection(db, 'users', uid, 'items')),
                    getDocs(collection(db, 'users', uid, 'printers')),
                    getDocs(collection(db, 'users', uid, 'payment_types')),
                    getDocs(query(collection(db, 'users', uid, 'tables'), orderBy('order'))),
                    getDocs(collection(db, 'users', uid, 'saved_tickets')),
                    getDocs(query(collection(db, 'users', uid, 'custom_grids'), orderBy('order')))
                ]);

                setItemsState(itemsSnap.docs.map(d => d.data() as Item));
                setPrintersState(printersSnap.docs.map(d => d.data() as Printer));
                setPaymentTypesState(ptSnap.docs.map(d => d.data() as PaymentType));
                setTablesState(tblSnap.docs.map(d => d.data() as Table));
                setSavedTicketsState(tktSnap.docs.map(d => d.data() as SavedTicket));
                setCustomGridsState(grdSnap.docs.map(d => d.data() as CustomGrid));
            } catch (e) { console.error("Initial load failed", e); }

            const unsubReceipts = onSnapshot(query(collection(db, 'users', uid, 'receipts'), orderBy('date', 'desc'), limit(50)), (snap) => {
                setReceiptsState(snap.docs.map(d => ({ ...d.data(), date: (d.data().date as Timestamp).toDate() } as Receipt)));
                setPendingSyncCount(snap.docs.filter(d => d.metadata.hasPendingWrites).length);
            });
            setIsLoading(false);
            return () => unsubReceipts();
        } else {
            setUser(null);
            setIsLoading(false);
        }
    });
    return () => unsubAuth();
  }, [setPendingSyncCount]);

  // Periodic Memory Cleanup: Ensures the app doesn't leak memory in long shifts
  useEffect(() => {
    const cleanupInterval = setInterval(() => {
        // Force memory release of old references if needed
        console.debug("Maintenance: Performing memory optimization check...");
    }, 1800000); // Every 30 minutes
    return () => clearInterval(cleanupInterval);
  }, []);

  const addReceipt = useCallback(async (receipt: Receipt) => {
    // 1. DATA STRIPPING (BEST PRACTICE): Never store Base64 images in receipts.
    // This keeps the receipt database lightweight and syncing fast.
    const persistenceFriendlyReceipt = {
        ...receipt,
        items: receipt.items.map(item => {
            const { imageUrl, ...rest } = item;
            return { ...rest, imageUrl: '' };
        })
    };

    setReceiptsState(prev => [receipt, ...prev].slice(0, 100)); // Keep local state lean
    idb.saveReceipt(persistenceFriendlyReceipt); 
    const batch = writeBatch(db);
    batch.set(doc(db, 'users', user!.uid, 'receipts', receipt.id), persistenceFriendlyReceipt);

    const updatedItems = [...items];
    receipt.items.forEach(orderItem => {
        const idx = updatedItems.findIndex(i => i.id === orderItem.id);
        if (idx > -1) {
            updatedItems[idx].stock = Math.max(0, updatedItems[idx].stock - orderItem.quantity);
            batch.update(doc(db, 'users', user!.uid, 'items', orderItem.id), { stock: increment(-orderItem.quantity) });
            if (settings.notifyLowStock && updatedItems[idx].stock <= (settings.lowStockThreshold || 0)) {
                sendLowStockAlert(updatedItems[idx].name, updatedItems[idx].stock);
            }
        }
    });
    setItemsState(updatedItems);
    try { await batch.commit(); } catch (e) { console.warn("Sync deferred (Offline mode active)"); }
  }, [user, items, settings]);

  const value = useMemo(() => ({
      user, signOut: signOutUser,
      isDrawerOpen, openDrawer, closeDrawer, toggleDrawer, 
      headerTitle, setHeaderTitle, theme, setTheme,
      showOnboarding, completeOnboarding: async () => {
          if (Capacitor.isNativePlatform()) {
              const p = await requestAppPermissions();
              await requestNotificationPermission();
              if (!p) return false;
          }
          localStorage.setItem(ONBOARDING_COMPLETED_KEY, 'true');
          setShowOnboarding(false);
          return true;
      },
      isLoading, settings, updateSettings: async (s: Partial<AppSettings>) => {
          const next = { ...settings, ...s };
          setSettingsState(next);
          localStorage.setItem(SETTINGS_CACHE_KEY, JSON.stringify(next));
          await setDoc(doc(db, 'users', user!.uid, 'config', 'settings'), next, { merge: true });
      },
      printers, addPrinter: async (p: Printer) => {
          setPrintersState(v => [...v, p]);
          await setDoc(doc(db, 'users', user!.uid, 'printers', p.id), p);
      },
      removePrinter: async (id: string) => {
          setPrintersState(v => v.filter(p => p.id !== id));
          await deleteDoc(doc(db, 'users', user!.uid, 'printers', id));
      },
      paymentTypes, addPaymentType: async (p: any) => {
          const id = `pt_${Date.now()}`;
          const pt = { ...p, id, enabled: true, type: 'other' };
          setPaymentTypesState(v => [...v, pt]);
          await setDoc(doc(db, 'users', user!.uid, 'payment_types', id), pt);
      },
      updatePaymentType: async (p: PaymentType) => {
          setPaymentTypesState(v => v.map(i => i.id === p.id ? p : i));
          await setDoc(doc(db, 'users', user!.uid, 'payment_types', p.id), p);
      },
